  'ganzhou/pavilion': ('Đình Úc Cô', 'Từng được các thi sĩ thời Tống ca ngợi, ngôi đình này có tầm nhìn bao quát nơi giao thoa của dòng sông.'),
  'ganzhou/star': ('Vạn lý Trường chinh', 'Cuộc Vạn lý Trường chinh của Hồng quân Trung Quốc đã bắt đầu từ chính thành phố này.'),
  'putian/shrine': ('Đền thờ Mẹ Mẫu', 'Nữ thần Mẹ Mẫu, vị thần bảo hộ ngư dân, đã sinh ra tại đây và ngôi đền thờ chính của bà tọa lạc trên đảo Mi Châu.'),
  'putian/lychee': ('Vườn vải', 'Những gốc vải nghìn năm tuổi đã mang lại cho thành phố này danh xưng là xứ sở của vải thiều.'),
  'putian/shoe': ('Thủ phủ giày dép', 'Một phần lớn sản lượng giày thể thao trên thế giới được sản xuất tại các xưởng ở thành phố này.'),
  'putian/wave': ('Đảo Mi Châu', 'Hòn đảo này nổi tiếng với những bãi biển thơ mộng và các lễ hội đền chùa đặc sắc, có thể di chuyển đến bằng phà.'),
  'mudanjiang/snow': ('Làng Tuyết', 'Ngôi làng cổ tích này được bao phủ bởi những lớp tuyết dày trắng xóa, tỏa sáng rực rỡ trong mùa đông.'),
  'mudanjiang/lake': ('Hồ Kính Bạc', 'Đây là một hồ nước chắn ngang do núi lửa tạo thành, nơi có thác nước Điếu Thủy Lâu vẫn đổ nước ngay cả trong mùa đông.'),
  'mudanjiang/tiger': ('Công viên Hổ Siberia', 'Đây là một trong những khu bảo tồn hổ Siberia lớn nhất trên thế giới.'),
  'mudanjiang/ski': ('Mùa trượt tuyết', 'Mùa đông dài với tuyết phủ dày đặc đã đưa khu vực này trở thành điểm đến không thể bỏ qua của những người yêu trượt tuyết.'),
  'changzhou/dino': ('Công viên Khủng long', 'Công viên chủ đề về khủng long nổi tiếng nhất Trung Quốc này là biểu tượng du lịch gia đình của thành phố.'),
  'changzhou/pagoda': ('Chùa Thiên Ninh', 'Với chiều cao 153 mét, đây là ngôi chùa cao nhất thế giới nằm ngay trung tâm thành phố.'),
  'changzhou/comb': ('Nghề làm lược', 'Những chiếc lược Thường Châu với lịch sử ngàn năm từng là món quà quý giá được dâng lên cung đình.'),
  'changzhou/canal': ('Đại Vận Hà', 'Dọc theo bờ kênh là nơi lý tưởng để tản bộ, ngắm nhìn những khu phố cổ và ánh đèn đêm lung linh.'),
  'shaoxing/wine': ('Rượu Thiệu Hưng', 'Loại rượu gạo vàng trứ danh trong ẩm thực Trung Hoa này đã được ủ tại đây suốt hàng ngàn năm qua.'),
  'shaoxing/bridge': ('Cầu đá cổ', 'Với hệ thống kênh rạch chằng chịt, Thiệu Hưng vẫn lưu giữ hàng trăm cây cầu đá vòm cổ kính.'),
  'shaoxing/pen': ('Cái nôi thư pháp', 'Lan Đình của thư pháp gia Vương Hy Chi được coi là thánh địa của nghệ thuật thư pháp.'),
  'shaoxing/boat': ('Thuyền Ô Bồng', 'Những chiếc thuyền Ô Bồng chèo bằng chân là phương tiện di chuyển đặc trưng trên các con kênh ở đây.'),
  'bengbu/shell': ('Cảng Ngọc Trai', 'Tên gọi của thành phố có nghĩa là \'bến hàu\', nơi từng nổi tiếng với những viên ngọc trai quý giá từ sông Hoài.'),
  'bengbu/train': ('Cửa ngõ đường sắt', 'Thành phố này phát triển mạnh mẽ nhờ vị trí là điểm giao cắt quan trọng của tuyến đường sắt Bắc-Nam qua sông Hoài.'),
  'bengbu/river': ('Sông Hoài', 'Đây chính là dòng sông đóng vai trò là ranh giới tự nhiên phân chia miền Bắc và miền Nam Trung Quốc.'),
  'bengbu/blossom': ('Lễ hội hoa xuân', 'Mỗi độ xuân về, các công viên ven sông lại tưng bừng tổ chức những lễ hội hoa rực rỡ.'),
  'jiujiang/mountain': ('Lư Sơn', 'Những đỉnh núi mờ sương của Lư Sơn, di sản thế giới được UNESCO công nhận, là nguồn cảm hứng bất tận cho thi ca và hội họa.'),
  'jiujiang/tea': ('Trà Vân Vụ', 'Loại trà Vân Vụ trồng trên sườn núi Lư Sơn được mệnh danh là một trong những loại trà tinh tế nhất Trung Hoa.'),
  'jiujiang/lake': ('Hồ Bà Dương', 'Hồ nước ngọt lớn nhất Trung Quốc này là nơi trú ngụ của hàng ngàn con sếu vào mỗi mùa đông.'),
  'jiujiang/scroll': ('Thành phố thi ca', 'Cửa ngõ ven sông này từng là nơi lưu dấu những vần thơ bất hủ của các thi hào Bạch Cư Dị và Tô Thức.'),
  'quanzhou/ship': ('Con đường tơ lụa trên biển', 'Từng được Marco Polo gọi là \'Zayton\', đây là thương cảng sầm uất nhất thế giới thời trung cổ và hiện là di sản UNESCO.'),
  'quanzhou/mosque': ('Thánh đường Thanh Tịnh', 'Được xây dựng từ năm 1009, đây là một trong những thánh đường Hồi giáo cổ xưa nhất tại Trung Quốc.'),
  'quanzhou/puppet': ('Múa rối dây', 'Nghệ thuật múa rối dây Tuyền Châu là một truyền thống sân khấu lâu đời đã tồn tại hàng ngàn năm.'),
  'quanzhou/tea': ('Trà Thiết Quan Âm', 'Loại trà ô long trứ danh từ vùng An Khê lân cận được thế giới biết đến với cái tên \'Nữ thần sắt\'.'),
  'shanghai/pearl': ('Tháp truyền hình Minh Châu Phương Đông', 'Với những khối cầu màu hồng vươn cao bên sông Hoàng Phố, tòa tháp này là biểu tượng cho sự hiện đại của Thượng Hải.'),
  'shanghai/bund': ('Bến Thượng Hải', 'Dãy kiến trúc lịch sử dọc bờ sông phản chiếu vẻ đẹp huy hoàng của Thượng Hải thời xưa.'),
  'shanghai/garden': ('Dự Viên', 'Khu vườn cổ thời nhà Minh với những hòn non bộ và ao hồ này là một ốc đảo bình yên giữa lòng thành phố.'),
  'shanghai/xlb': ('Tiểu long bao', 'Những chiếc bánh bao hấp chứa đầy nước dùng nóng hổi là món điểm tâm tinh túy nhất của người Thượng Hải.'),
  'hangzhou/lake': ('Tây Hồ', 'Với những hàng liễu, đảo nhỏ và cầu vòm, đây là hồ nước được ca ngợi nhiều nhất trong thi ca Trung Hoa.'),
  'hangzhou/tea': ('Trà Long Tỉnh', 'Được trồng trên các sườn đồi quanh hồ, loại trà xanh \'Giếng Rồng\' này là danh trà nổi tiếng nhất Trung Quốc.'),
  'hangzhou/temple': ('Chùa Linh Ẩn', 'Ngôi chùa 1.700 năm tuổi này nổi tiếng với các tác phẩm điêu khắc trên đá và tượng Phật khổng lồ.'),
  'hangzhou/silk': ('Phố lụa Hàng Châu', 'Lụa Hàng Châu đã được dệt suốt hàng ngàn năm, tạo nên sự thịnh vượng cho điểm cuối phía đông của Con đường Tơ lụa.'),
  'chongqing/hongya': ('Hồng Nhai Động', 'Tổ hợp nhà sàn rực rỡ bám vào vách đá này trông như một tòa lâu đài cổ tích tỏa sáng bên bờ sông vào ban đêm.'),
  'chongqing/hotpot': ('Lẩu Trùng Khánh', 'Với nước dùng sôi sùng sục đầy ớt và tiêu tê, lẩu chính là linh hồn cay nồng của thành phố núi này.'),
  'chongqing/monorail': ('Đường sắt trên cao Trùng Khánh', 'Tuyến đường sắt chạy xuyên qua tòa nhà là hình ảnh biểu tượng của thành phố được xây dựng trên những ngọn đồi này.'),
  'chongqing/river': ('Tam Hiệp Trường Giang', 'Các chuyến du thuyền Tam Hiệp khởi hành từ bến cảng nơi thành phố trỗi dậy tại điểm giao thoa của hai dòng sông.'),
  'dalian/square': ('Quảng trường Tinh Hải', 'Quảng trường thành phố lớn nhất châu Á này là nơi diễn ra nhiều lễ hội và chương trình biểu diễn dọc bờ biển.'),
  'dalian/beach': ('Bãi biển Đại Liên', 'Với những vịnh đá và mùa hè mát mẻ, Đại Liên là khu nghỉ dưỡng ven biển được yêu thích nhất ở miền Bắc.'),
  'dalian/football': ('Thành phố bóng đá', 'Được mệnh danh là \'cái nôi của bóng đá Trung Quốc\', đây là nơi ra đời của những câu lạc bộ giàu thành tích nhất cả nước.'),
  'dalian/seafood': ('Hải sản Đại Liên', 'Các loại sò điệp, tôm và nhím biển từ vùng biển Hoàng Hải lạnh giá luôn là món ngon trên bàn ăn của thành phố.'),
  'shenyang/palace': ('Thẩm Dương Cố Cung', 'Đây là cung điện đầu tiên của nhà Thanh, được coi như người anh em nhỏ hơn của Tử Cấm Thành ở Bắc Kinh.'),
  'shenyang/tomb': ('Lăng mộ nhà Thanh', 'Các khu lăng mộ phía Đông và phía Bắc bao quanh thành phố là những công trình tưởng niệm hoành tráng của các vị hoàng đế khai quốc.'),
  'shenyang/factory': ('Cái nôi công nghiệp', 'Nền công nghiệp nặng của Trung Quốc khởi nguồn từ đây, với những nhà máy khổng lồ giúp thành phố được mệnh danh là \'vùng Ruhr của phương Đông\'.'),
  'shenyang/dumpling': ('Sủi cảo Lão Biên', 'Món sủi cảo hấp Lão Biên với lịch sử hơn 200 năm là đặc sản trứ danh trên bàn tiệc phương Bắc.'),
  'hefei/judge': ('Bao Công Từ', 'Là quê hương của vị quan thanh liêm Bao Chửng, ngôi đền này chính là biểu tượng cho đức tính chính trực.'),
  'hefei/science': ('Thành phố Khoa học', 'Đây là trung tâm công nghệ quy tụ nhiều trường đại học và phòng thí nghiệm hàng đầu của Trung Quốc.'),
  'hefei/lake': ('Hồ Sào', 'Một trong năm hồ nước ngọt lớn nhất Trung Quốc, nổi tiếng với đặc sản cá trắng và cua.'),
  'hefei/cake': ('Bánh mè Lư Châu', 'Loại bánh mè nhân ngọt này là món ăn vặt truyền thống lâu đời của vùng đất Lư Châu xưa.'),
  'foshan/wingchun': ('Vịnh Xuân Quyền', 'Phật Sơn là cái nôi của võ thuật Vịnh Xuân, nơi khởi nguồn của những huyền thoại như Diệp Vấn và Lý Tiểu Long.'),
  'foshan/lion': ('Múa lân', 'Được mệnh danh là thủ phủ múa lân phương Nam, nơi những chú lân rực rỡ sắc màu nhảy múa trên các cột cao trong lễ hội.'),
  'foshan/ceramic': ('Gốm Thạch Loan', 'Những lò nung nghìn năm tuổi vẫn tiếp tục cho ra đời các bức tượng gốm Thạch Loan đầy sống động.'),
  'foshan/opera': ('Kịch Quảng Đông', 'Loại hình nghệ thuật sân khấu được yêu thích nhất miền Nam Trung Quốc đã phát triển rực rỡ trên mảnh đất này.'),
  'guiyang/pavilion': ('Giáp Tú Các', 'Tòa lầu ba tầng nằm bên dòng sông Nam Minh này đã trở thành biểu tượng của thành phố suốt 400 năm qua.'),
  'guiyang/sourfish': ('Cá nấu canh chua', 'Món cá nấu trong nước dùng cà chua lên men chua dịu là đặc sản mang đậm hương vị Quý Châu.'),
  'guiyang/waterfall': ('Thác Hoàng Quả Thụ', 'Một trong những thác nước lớn nhất châu Á đổ xuống ầm ầm, tạo nên những dải cầu vồng rực rỡ.'),
  'guiyang/miao': ('Văn hóa người Miêu', 'Những lễ hội và nghề thêu thùa của người Miêu với trang phục đội vương miện bạc đã làm bừng sáng các bản làng vùng núi.'),
  'changchun/film': ('Thành phố Điện ảnh', 'Nơi đây được coi là \'Hollywood của phương Đông\', cái nôi khai sinh ra nền điện ảnh Trung Quốc.'),
  'changchun/car': ('Thành phố Ô tô', 'Đây là thủ phủ ô tô của cả nước, nơi những chiếc xe hơi đầu tiên do Trung Quốc tự sản xuất đã ra đời.'),
  'changchun/palace': ('Ngụy Mãn Hoàng cung', 'Nơi ở của vị hoàng đế cuối cùng là nhân chứng thầm lặng cho một giai đoạn lịch sử đầy biến động.'),
  'changchun/snow': ('Tuyết mùa đông', 'Suốt mùa đông dài trắng xóa, thành phố bừng sáng với những tác phẩm điêu khắc băng và các đường trượt tuyết.'),
  'xining/lake': ('Hồ Thanh Hải', 'Hồ nước mặn lớn nhất Trung Quốc nổi tiếng với những cánh đồng hoa cải vàng rực rỡ bao quanh vào mùa hè.'),
  'xining/monastery': ('Tu viện Kumbum', 'Một trong sáu tu viện lớn nhất của Phật giáo Tây Tạng, nổi danh với những tác phẩm điêu khắc từ bơ bò yak.'),
  'xining/flower': ('Hoa cải dầu', 'Vào tháng Bảy, cả cao nguyên như được bao phủ bởi những cánh đồng hoa cải vàng óng trải dài đến tận chân trời.'),
  'xining/lamb': ('Thịt bò yak và thịt cừu', 'Mì kéo tay và thịt cừu xiên nướng mang đậm phong vị ẩm thực Hồi giáo và Tây Tạng là đặc sản của vùng cao nguyên này.'),
  'guilin/karst': ('Núi đá vôi sông Ly', 'Những ngọn núi đá vôi nhô lên từ làn sương mờ ảo chính là khung cảnh được in trên tờ tiền 20 nhân dân tệ.'),
  'guilin/elephant': ('Núi Vòi Voi', 'Tảng đá có hình dáng như chú voi đang cúi vòi xuống dòng sông là biểu tượng thân thương của thành phố.'),
  'guilin/terrace': ('Ruộng bậc thang Long Tích', 'Những thửa ruộng bậc thang \'Sống lưng rồng\' uốn lượn trên sườn núi là minh chứng cho hàng thế kỷ lao động miệt mài.'),
  'guilin/osmanthus': ('Hoa mộc tê', 'Tên gọi của thành phố có nghĩa là \'rừng hoa mộc\', nơi vào mùa thu tràn ngập hương thơm ngọt ngào của loài hoa này.'),
  'wenzhou/merchant': ('Tinh thần thương nhân', 'Được ví như \'người Do Thái của Trung Quốc\', các doanh nhân Ôn Châu đã xây dựng mạng lưới kinh doanh trên khắp thế giới.'),
  'wenzhou/shoe': ('Giày dép và đồ da', 'Một phần lớn sản lượng giày da trên thế giới được sản xuất từ thành phố công nghiệp này.'),
  'wenzhou/mountain': ('Núi Nhạn Đãng', 'Nổi tiếng với những thác nước và đỉnh núi hiểm trở, nơi đây được ca ngợi là \'đệ nhất danh sơn bên bờ biển\'.'),
  'wenzhou/seafood': ('Hải sản', 'Mực, sò điệp và các loại cá từ biển Hoa Đông là nguyên liệu chính trong các bữa ăn của người dân địa phương.'),
  'tangshan/memorial': ('Đài tưởng niệm động đất', 'Công viên tưởng niệm trận động đất lớn năm 1976 là biểu tượng cho sự hồi sinh mạnh mẽ của thành phố.'),
  'tangshan/coal': ('Than đá và thép', 'Đây là cái nôi của ngành công nghiệp hiện đại Trung Quốc, nơi khai thác mỏ than và tuyến đường sắt đầu tiên của đất nước.'),
  'tangshan/ceramic': ('Gốm sứ Đường Sơn', 'Được mệnh danh là \'thành phố gốm sứ phương Bắc\', các sản phẩm sứ xương tại đây nổi tiếng với vẻ đẹp thanh tao và tinh tế.'),
  'tangshan/lake': ('Công viên Nam Hồ', 'Khu công viên hồ nước này vốn được cải tạo từ một hố mỏ cũ, nay đã trở thành lá phổi xanh của cả thành phố.'),
  'anshan/steel': ('Thành phố Thép', 'Nơi đây là \'thủ phủ thép\' của Trung Quốc, đồng thời là cái nôi của khu liên hợp sản xuất thép lớn nhất cả nước.'),
  'anshan/jade': ('Ngọc Tú Nham', 'Thành phố này được coi là vùng đất ngọc của Trung Quốc, nơi lưu giữ tác phẩm điêu khắc bằng ngọc lớn nhất thế giới.'),
  'anshan/mountain': ('Núi Thiên Sơn', 'Với những ngôi chùa cổ và vách đá hùng vĩ, \'Thiên Sơn\' được coi là ngọn núi linh thiêng bậc nhất ở phương Bắc.'),
  'anshan/spring': ('Suối nước nóng Thang Cương Tử', 'Nguồn suối nước nóng này đã được sử dụng để chữa bệnh suốt hàng ngàn năm qua và từng là nơi nghỉ dưỡng của các bậc hoàng đế.'),
  'linyi/market': ('Chợ bán buôn Lâm Nghi', 'Đây là trung tâm bán buôn lớn nhất miền Bắc Trung Quốc, chuyên phân phối hàng hóa đi khắp cả nước.'),
  'linyi/brush': ('Quê hương thư pháp', 'Lâm Nghi là nơi sinh của Vương Hy Chi - \'Thánh thư pháp\' của Trung Quốc, vì vậy thành phố này còn được gọi là vùng đất của mực và bút.'),
  'linyi/mountain': ('Núi Mông Sơn', 'Là ngọn núi cao thứ hai ở tỉnh Sơn Đông, nơi đây được ví như một \'phòng oxy\' tự nhiên với không khí trong lành và những thác nước tuyệt đẹp.'),
  'linyi/pancake': ('Bánh xèo Nghi Mông', 'Món bánh xèo làm từ bột ngô này là món ăn truyền thống lâu đời của người dân vùng núi Nghi Mông.'),
  'cangzhou/lion': ('Sư tử sắt Thương Châu', 'Bức tượng sư tử đúc bằng sắt khổng lồ có lịch sử hơn 1.100 năm này là niềm tự hào biểu tượng của thành phố.'),
  'cangzhou/martial': ('Võ thuật Thương Châu', 'Thương Châu được mệnh danh là \'quê hương của võ thuật\' tại Trung Quốc, nơi sản sinh ra nhiều võ sư và các trường phái võ thuật nổi tiếng.'),
  'cangzhou/canal': ('Đại Vận Hà', 'Kênh đào Đại Vận Hà Bắc Kinh - Hàng Châu chảy qua thành phố, nơi vẫn còn lưu giữ những bến tàu cổ kính.'),
  'cangzhou/jujube': ('Táo tàu vàng', 'Loại táo tàu \'tơ vàng\' với lớp vỏ mỏng và vị ngọt thanh này được mệnh danh là vua của các loại trái cây sấy khô.'),
  'nantong/textile': ('Thành phố Dệt may', 'Được mệnh danh là thủ phủ dệt may của Trung Quốc, các sản phẩm vải bông tại đây đã vươn tầm ra thị trường thế giới.'),
  'nantong/mountain': ('Núi Lang', 'Ngọn núi thiêng với năm đỉnh nhấp nhô nằm ngay cửa sông Dương Tử này là điểm đến hành hương và ngắm cảnh nổi tiếng.'),
  'nantong/kite': ('Diều sáo', 'Những chiếc diều sáo \'banyao\' với âm thanh vi vu đặc trưng là một loại hình thủ công truyền thống lâu đời của thành phố.'),
  'nantong/school': ('Cái nôi giáo dục', 'Nhà công nghiệp Trương Kiên đã thành lập những ngôi trường hiện đại và bảo tàng đầu tiên của Trung Quốc tại nơi đây.'),
  'taizhou/opera': ('Mai Lan Phương', 'Đây chính là quê hương của Mai Lan Phương, bậc thầy huyền thoại của nghệ thuật Kinh kịch.'),
  'taizhou/tea': ('Trà sáng', 'Thưởng thức trà sáng cùng các loại bánh bao hấp đã trở thành một nét văn hóa ẩm thực đặc trưng của người dân nơi đây.'),
  'taizhou/boat': ('Lễ hội đua thuyền Cần Đồng', 'Vào mùa xuân, lễ hội với hàng trăm tay chèo tranh tài đã mang đến sức sống mãnh liệt cho dòng sông.'),
  'taizhou/meatball': ('Thịt viên đầu sư tử', 'Món thịt viên mềm mại, thơm ngon này là một trong những đại diện tiêu biểu của ẩm thực Hoài Dương.'),
  'jinhua/ham': ('Giăm bông Kim Hoa', 'Được chế biến bằng phương pháp truyền thống hàng thế kỷ, đây là loại giăm bông nổi tiếng nhất tại Trung Quốc.'),
  'jinhua/film': ('Phim trường Hoành Điếm', 'Đây là phim trường ngoài trời lớn nhất thế giới, nơi ghi hình cho vô số bộ phim cổ trang nổi tiếng.'),
  'jinhua/cave': ('Động Song Long', 'Du khách sẽ được trải nghiệm cảm giác choáng ngợp khi đi thuyền qua cửa hang đá thấp để tiến vào hang động ngầm kỳ vĩ này.'),
  'jinhua/bridge': ('Cầu cổ', 'Những cây cầu đá vòm cùng các thị trấn ven sông mang đậm nét duyên dáng đặc trưng của vùng Giang Nam.'),
  'wuhu/park': ('Công viên giải trí Phương Đặc', 'Là một trong những công viên giải trí lớn nhất Trung Quốc, nơi đây mang đến cho các gia đình những ngày vui chơi đầy phấn khích.'),
  'wuhu/ironart': ('Tranh sắt', 'Những bức tranh sắt tinh xảo được rèn từ sắt uốn là một loại hình nghệ thuật thủ công có lịch sử 300 năm.'),
  'wuhu/rice': ('Cảng gạo', 'Thành phố nằm bên bờ sông Dương Tử này từng là thị trường gạo lớn nhất của Trung Quốc trong lịch sử.'),
  'wuhu/river': ('Cảng Dương Tử', 'Đây là một cảng sông sầm uất, đóng vai trò là cửa ngõ thông ra biển của tỉnh An Huy.'),
  'huangshan/peak': ('Hoàng Sơn', 'Với những đỉnh núi đá granite, biển mây bồng bềnh và những cây thông cổ thụ, đây là ngọn núi nổi tiếng nhất Trung Quốc.'),
  'huangshan/village': ('Thôn Hoành', 'Ngôi làng mang phong cách kiến trúc Huy Châu với tường trắng, mái ngói và hệ thống kênh rạch này đã được UNESCO công nhận là di sản thế giới.'),
  'huangshan/tea': ('Trà Mao Phong', 'Được hái trên những sườn núi mờ sương, loại trà xanh với búp non phủ lông tơ này là một trong mười loại trà danh tiếng nhất Trung Quốc.'),
  'huangshan/ink': ('Mực và nghệ thuật Huy Châu', 'Mực Huy Châu, các công trình kiến trúc gỗ chạm khắc và nghệ thuật thư pháp là những báu vật văn hóa đặc sắc của vùng đất này.'),
  'yichun/moon': ('Núi Minh Nguyệt', 'Ngọn núi \'Trăng Sáng\' này nổi tiếng với các suối nước nóng và tầm nhìn tuyệt đẹp từ cáp treo.'),
  'yichun/spring': ('Suối nước nóng', 'Những suối nước nóng giàu selen quý hiếm đã biến nơi đây thành trung tâm tắm khoáng hàng đầu Trung Quốc.'),
  'yichun/zen': ('Thiền tông', 'Những ngôi chùa cổ nằm sâu trong núi, nơi khởi nguồn của các tông phái Thiền tông Trung Hoa, mang đến không gian tĩnh lặng tuyệt đối.'),
  'yichun/rice': ('Đồng bằng Viên Hà', 'Vùng đồng bằng Viên Hà màu mỡ từ lâu đã được coi là vựa lúa của tỉnh Giang Tây.'),
  'zhangzhou/narcissus': ('Hoa thủy tiên', 'Đây là nơi trồng hoa thủy tiên nổi tiếng nhất Trung Quốc, loài hoa biểu tượng cho các dịp lễ hội mùa xuân.'),
  'zhangzhou/tulou': ('Thổ lâu Khách Gia', 'Những pháo đài bằng đất nện hình tròn khổng lồ này là di sản UNESCO, nơi cả một ngôi làng cùng sinh sống dưới một mái nhà.'),
  'zhangzhou/banana': ('Trái cây nhiệt đới', 'Những vườn chuối, nhãn và quýt giúp vùng đồng bằng ấm áp này luôn xanh tươi quanh năm.'),
  'zhangzhou/coast': ('Đảo Đông Sơn', 'Với những bãi biển vàng óng và các làng chài yên bình, hòn đảo này được ví như viên ngọc quý của vùng duyên hải phía Nam.'),
  'guangzhou/tower': ('Tháp Quảng Châu', 'Được mệnh danh là \'Eo thon\', đây là một trong những tòa tháp cao nhất thế giới, rực rỡ sắc màu mỗi khi đêm về.'),
  'guangzhou/dimsum': ('Điểm sấm', 'Thưởng thức điểm sấm trong những xửng tre nóng hổi cùng trà đạo là linh hồn trong văn hóa ẩm thực của người Quảng Đông.'),
  'guangzhou/academy': ('Từ đường dòng họ Trần', 'Nổi tiếng với các tác phẩm chạm khắc gỗ và phù điêu gốm sứ tinh xảo, từ đường này là một kiệt tác của nghệ thuật thủ công Quảng Đông.'),
  'guangzhou/flower': ('Thành phố Hoa', 'Với hoa nở quanh năm và các hội chợ hoa quy mô lớn mỗi dịp Tết, Quảng Châu được mệnh danh là \'Thành phố Hoa\'.'),
  'wuhan/crane': ('Hoàng Hạc Lâu', 'Tọa lạc bên bờ sông Dương Tử, tòa tháp nghìn năm tuổi này là nguồn cảm hứng cho những bài thơ nổi tiếng nhất Trung Quốc.'),
  'wuhan/noodle': ('Mì khô nóng', 'Mì khô nóng trộn sốt mè là món ăn sáng không thể thiếu của người dân Vũ Hán.'),
  'wuhan/duckneck': ('Cổ vịt cay', 'Cổ vịt om cay là món ăn vặt khoái khẩu của người dân địa phương trong những buổi trò chuyện đêm khuya.'),
  'wuhan/university': ('Hoa anh đào Đại học Vũ Hán', 'Mùa hoa anh đào tại Đại học Vũ Hán thu hút hàng nghìn du khách ghé thăm mỗi độ xuân về.'),
  'tianjin/eye': ('Mắt Thiên Tân', 'Đây là vòng quay mặt trời được xây dựng ngay trên cầu, cho phép du khách ngắm nhìn toàn cảnh hai bên bờ sông.'),
  'tianjin/baozi': ('Bánh bao Cẩu Bất Lý', 'Món bánh bao nhân thịt hấp với lớp vỏ xếp nếp tinh tế là đặc sản trứ danh có lịch sử 150 năm của thành phố.'),
  'tianjin/crosstalk': ('Tướng thanh', 'Tướng thanh là loại hình hài kịch đối thoại truyền thống của Thiên Tân, bắt nguồn từ các quán trà xưa.'),
  'tianjin/architecture': ('Khu phố kiến trúc châu Âu', 'Những biệt thự mang phong cách châu Âu tại Ngũ Đại Đạo đã giúp Thiên Tân được ví như một \'bảo tàng kiến trúc\'.'),
  'xiamen/island': ('Đảo Cổ Lãng Tự', 'Với những con đường không bóng xe cộ và các biệt thự cổ kính, hòn đảo được UNESCO công nhận này giống như một bảo tàng ngoài trời.'),
  'xiamen/piano': ('Đảo Dương cầm', 'Nhờ sở hữu số lượng đàn piano trên đầu người cao nhất cả nước, Cổ Lãng Tự còn được gọi là \'đảo dương cầm\'.'),
  'xiamen/egret': ('Cò trắng', 'Cò trắng là biểu tượng của thành phố, gợi nhắc về tên gọi cũ \'đảo cò\' của Hạ Môn.'),
  'xiamen/oyster': ('Trứng chiên hàu', 'Món trứng chiên hàu tươi giòn là ngôi sao trong nền ẩm thực vùng ven biển này.'),
  'harbin/ice': ('Lễ hội Băng đăng', 'Lễ hội mùa đông với những cung điện băng khổng lồ rực rỡ ánh đèn tại đây là lễ hội lớn nhất thế giới.'),
  'harbin/cathedral': ('Nhà thờ Thánh Sophia', 'Nhà thờ Chính thống giáo Nga với mái vòm hình củ hành này là biểu tượng cho lịch sử mang đậm dấu ấn châu Âu của thành phố.'),
  'harbin/sausage': ('Xúc xích đỏ', 'Món xúc xích đỏ hun khói theo phong cách Nga là đặc sản có lịch sử trăm năm của thành phố này.'),
  'harbin/accordion': ('Thành phố âm nhạc', 'Với di sản văn hóa Nga sâu đậm, Cáp Nhĩ Tân là nơi thành lập dàn nhạc giao hưởng đầu tiên của Trung Quốc.'),
  'fuzhou/alley': ('Tam Phường Thất Ngõ', 'Khu phố cổ với tường trắng ngói đen này là một bảo tàng sống động về kiến trúc thời Minh - Thanh.'),
  'fuzhou/banyan': ('Thành phố cây đa', 'Những cây đa cổ thụ khổng lồ tỏa bóng mát khắp các con phố, khiến Phúc Châu được mệnh danh là \'thành phố cây đa\'.'),
  'fuzhou/hotspring': ('Suối nước nóng', 'Các mạch nước nóng tự nhiên chảy ngay trong lòng thành phố đã phục vụ các nhà tắm công cộng suốt cả ngàn năm qua.'),
  'fuzhou/soup': ('Phật nhảy tường', 'Được hầm từ hàng chục loại nguyên liệu thượng hạng, món súp này là kiệt tác đỉnh cao của ẩm thực Phúc Kiến.'),
  'dongguan/robot': ('Công xưởng thế giới', 'Với các nhà máy tự động hóa hiện đại, Đông Quản đóng góp một phần khổng lồ vào sản lượng đồ điện tử toàn cầu.'),
  'dongguan/basketball': ('Thành phố bóng rổ', 'Câu lạc bộ bóng rổ giàu thành tích nhất Trung Quốc đang thi đấu tại \'thành phố bóng rổ\' này.'),
  'dongguan/keyuan': ('Khả Viên', 'Đây là một trong bốn khu vườn cổ điển nổi tiếng nhất Quảng Đông, nổi tiếng với những hồ nước và đình đài tuyệt đẹp.'),
  'dongguan/cannon': ('Pháo đài Hổ Môn', 'Pháo đài Hổ Môn, nơi khởi đầu của Chiến tranh Nha phiến, đánh dấu bờ biển từng diễn ra sự kiện tiêu hủy thuốc phiện lịch sử.'),
  'lanzhou/beefnoodle': ('Mì bò Lan Châu', 'Với nước dùng bò trong vắt và sợi mì kéo tay đặc trưng, Lan Châu được coi là thủ phủ mì của Trung Quốc.'),
  'lanzhou/waterwheel': ('Guồng nước', 'Những chiếc guồng nước khổng lồ bên bờ sông Hoàng Hà là biểu tượng cho kỹ thuật tưới tiêu có từ hàng thế kỷ trước.'),
  'lanzhou/statue': ('Tượng Mẹ Hoàng Hà', 'Bức tượng mẹ và con bên bờ sông khắc họa hình ảnh dòng sông đã nuôi dưỡng nền văn minh Trung Hoa.'),
  'lanzhou/raft': ('Bè da cừu', 'Những chiếc bè truyền thống làm từ da cừu thổi phồng vẫn đang trôi trên dòng sông Hoàng Hà.'),
  'urumqi/bazaar': ('Đại Ba-za', 'Với những tòa tháp cao vút và các quầy gia vị sặc sỡ, khu chợ này mang đậm sắc màu của Con đường Tơ lụa.'),
  'urumqi/tianshan': ('Thiên Trì', 'Nằm dưới những đỉnh núi tuyết của dãy Thiên Sơn, hồ Thiên Trì được bao quanh bởi những cánh rừng vân sam xanh mướt.'),
  'urumqi/kebab': ('Thịt cừu xiên nướng', 'Thịt cừu tẩm ướp gia vị nướng trên than hồng là món ăn không thể thiếu trong bữa cơm của người Duy Ngô Nhĩ.'),
  'urumqi/dance': ('Điệu múa Duy Ngô Nhĩ', 'Những điệu múa xoay người uyển chuyển của người Duy Ngô Nhĩ trên nền nhạc trống và đàn rawap luôn làm bừng sáng mọi lễ hội.'),
  'haikou/coconut': ('Thành phố Dừa', 'Những con phố rợp bóng dừa đã mang lại cho Hải Khẩu biệt danh \'thành phố dừa\'.'),
  'haikou/arcade': ('Phố cổ Kỵ Lâu', 'Những tòa nhà \'kỵ lâu\' với hàng hiên có cột chống ở phương Nam tạo nên các con phố có mái che độc đáo.'),
  'haikou/crater': ('Miệng núi lửa', 'Các miệng núi lửa đã tắt tạo thành một công viên địa chất xanh mát ngay rìa thành phố.'),
  'haikou/turtle': ('Biển nhiệt đới', 'Làn nước trong xanh ấm áp cùng những rạn san hô đã biến vùng biển nơi đây thành ngôi nhà của loài rùa biển.'),
  'luoyang/grotto': ('Hang đá Long Môn', 'Hàng chục nghìn bức tượng Phật được chạm khắc trên vách đá tạo nên một kho tàng nghệ thuật được UNESCO công nhận.'),
  'luoyang/peony': ('Thủ phủ hoa mẫu đơn', 'Hàng nghìn đóa mẫu đơn đua nhau khoe sắc mỗi tháng Tư đã biến Lạc Dương thành \'thủ phủ hoa mẫu đơn\'.'),
  'luoyang/whitehorse': ('Chùa Bạch Mã', 'Được thành lập từ năm 68 sau Công nguyên, ngôi chùa này được coi là tu viện Phật giáo đầu tiên của Trung Quốc.'),
  'luoyang/capital': ('Cố đô', 'Từng là kinh đô của mười ba triều đại, Lạc Dương được xem là cái nôi của nền văn minh Trung Hoa.'),
  'shantou/gongfutea': ('Trà đạo Triều Sán', 'Được pha chế cầu kỳ trong những chén nhỏ, trà đạo Triều Sán là một nghệ thuật hiếu khách đặc sắc.'),
  'shantou/beefpot': ('Lẩu bò', 'Món lẩu bò Triều Sán nổi tiếng với những lát thịt bò tươi thái mỏng, chỉ cần nhúng trong vài giây là chín.'),
  'shantou/opera': ('Kịch Triều Châu', 'Loại hình kịch Triều Châu có lịch sử 600 năm nổi tiếng với những bài hát tinh tế và trang phục thêu thùa cầu kỳ.'),
  'shantou/harbor': ('Thành phố cảng Sán Đầu', 'Là quê hương của nhiều người Hoa hải ngoại, cảng biển này từng là cửa ngõ giao thương hàng hải lâu đời.'),
  'baoding/mansion': ('Phủ Tổng đốc Trực Lệ', 'Đây là cơ quan hành chính cấp tỉnh được bảo tồn nguyên vẹn nhất từ thời nhà Thanh.'),
  'baoding/donkeyburger': ('Bánh kẹp thịt lừa', 'Thịt lừa tẩm ướp gia vị kẹp trong lớp vỏ bánh giòn tan là món ăn đường phố đặc trưng của vùng này.'),
  'baoding/balls': ('Bóng tập dưỡng sinh', 'Việc xoay những quả cầu kim loại trong lòng bàn tay là một phương pháp tập luyện truyền thống có từ hàng trăm năm nay.'),
  'baoding/reeds': ('Đầm lầy Bạch Dương Điến', 'Đây là vùng đất ngập nước lớn nhất miền Bắc, được ví như thiên đường của các loài chim với bạt ngàn lau sậy và hoa sen.'),
  'jilin/rime': ('Băng giá Cát Lâm', 'Hiện tượng băng giá phủ trắng cây cối bên bờ sông Tùng Hoa là một trong bốn kỳ quan thiên nhiên của Trung Quốc.'),
  'jilin/snowboard': ('Khu nghỉ dưỡng trượt tuyết', 'Với lượng tuyết dày và mùa đông kéo dài, thành phố này là một trong những điểm trượt tuyết hàng đầu ở miền Bắc.'),
  'jilin/meteorite': ('Bảo tàng Thiên thạch', 'Nơi đây trưng bày thiên thạch đá lớn nhất thế giới, rơi xuống trái đất vào năm 1976.'),
  'jilin/skate': ('Sông Tùng Hoa đóng băng', 'Vào mùa đông, dòng sông Tùng Hoa đóng băng trở thành sân băng tự nhiên thu hút đông đảo người dân đến trượt băng và dạo chơi.'),
  'ordos/khan': ('Lăng mộ Thành Cát Tư Hãn', 'Ngôi lăng mộ tráng lệ tôn vinh vị anh hùng thảo nguyên Thành Cát Tư Hãn là trái tim của văn hóa Mông Cổ.'),
  'ordos/cashmere': ('Len Cashmere', 'Len Cashmere dệt từ lông dê Ordos đã đưa tên tuổi thành phố này vươn tầm thế giới trong ngành dệt may.'),
  'ordos/sanddune': ('Cồn cát biết hát', 'Những đồi cát khổng lồ phát ra âm thanh khi bạn trượt xuống là điểm dừng chân thú vị nhất tại sa mạc Kubuqi.'),
  'ordos/yurt': ('Lều Yurt Mông Cổ', 'Những chiếc lều nỉ trắng dựng trên thảo nguyên bao la là biểu tượng cho cuộc sống du mục.'),
  'jining/confucius': ('Đền thờ Khổng Tử', 'Nằm ở Khúc Phụ gần đó, quần thể đền thờ, dinh thự và mộ phần của Khổng Tử đã được UNESCO công nhận là di sản thế giới.'),
  'jining/barge': ('Đại Vận Hà', 'Từng là cảng thị sầm uất trên tuyến kênh đào Bắc Kinh - Hàng Châu, Tế Ninh là trung tâm văn hóa kênh đào quan trọng.'),
  'jining/sword': ('Các anh hùng Lương Sơn', '108 vị anh hùng hảo hán trong tác phẩm kinh điển Thủy Hử đã tụ hội tại vùng đồi núi đầm lầy này.'),
  'jining/fishnet': ('Hồ Vi Sơn', 'Trên mặt hồ sen lớn nhất phương Bắc, ngư dân vẫn ngày ngày quăng chài đánh cá theo phương thức truyền thống.'),
  'langfang/culture': ('Trung tâm Văn hóa Con đường Tơ lụa', 'Trung tâm văn hóa hiện đại quy mô lớn này là nơi hội tụ tinh hoa nghệ thuật của Con đường Tơ lụa.'),
  'langfang/furniture': ('Thành phố Nội thất', 'Hương Hà lân cận là một trong những trung tâm sản xuất và kinh doanh đồ nội thất lớn nhất Trung Quốc.'),
  'langfang/tunnel': ('Địa đạo Chiến tranh Cổ đại', 'Hệ thống địa đạo quân sự nghìn năm tuổi nằm sâu dưới lòng đất là minh chứng cho một tuyến phòng thủ biên giới xưa kia.'),
  'langfang/themepark': ('Công viên \'Đệ nhất Thành\'', 'Một công viên giải trí rộng lớn tái hiện lại hình ảnh thành cổ, là điểm đến lý tưởng cho các gia đình.'),
  'yancheng/salt': ('Diêm Thành', 'Tên gọi của thành phố có nghĩa là \'thành phố muối\', nơi từng là trung tâm sản xuất muối quan trọng của Trung Quốc trong nhiều thế kỷ.'),
  'yancheng/crane': ('Sếu đầu đỏ', 'Vùng đất ngập nước ven biển này là nơi trú đông lớn nhất thế giới của loài sếu đầu đỏ hoang dã.'),
  'yancheng/elk': ('Hươu Père David', 'Từng có nguy cơ tuyệt chủng trong tự nhiên, loài hươu Milu đã được nhân giống và phục hồi sự sống tại các vùng đất ngập nước này.'),
  'yancheng/wetland': ('Đất ngập nước ven biển', 'Những bãi bồi ven biển được UNESCO công nhận là điểm dừng chân quan trọng trên toàn cầu của các loài chim di cư.'),
  'huzhou/brush': ('Bút Hồ', 'Bút Hồ, một trong \'văn phòng tứ bảo\' của nghệ thuật thư pháp Trung Hoa, được chế tác tại chính nơi này.'),
  'huzhou/bamboo': ('Rừng trúc An Cát', 'Những rừng trúc xanh mướt trải dài vô tận, từng là nguồn cảm hứng cho nhiều bộ phim, giúp không khí nơi đây luôn mát mẻ.'),
  'huzhou/silkworm': ('Tằm tơ', 'Bờ nam hồ Thái Hồ đã trở thành trung tâm sản xuất tơ tằm từ lá dâu tằm suốt hàng nghìn năm qua.'),
  'huzhou/whitetea': ('Trà trắng An Cát', 'Với lá trà màu nhạt và hương vị ngọt thanh, trà trắng An Cát được xếp vào hàng những loại trà quý hiếm nhất Trung Quốc.'),
  'quzhou/go': ('Cờ vây', 'Gắn liền với truyền thuyết về núi Lạn Kha, thành phố này được tôn vinh là \'vùng đất của cờ vây\'.'),
  'quzhou/peaks': ('Núi Giang Lang', 'Ba cột đá khổng lồ vươn thẳng lên trời tạo nên một cảnh quan độc đáo được UNESCO công nhận.'),
  'quzhou/ponkan': ('Quýt đường Cù Châu', 'Loại quýt có lớp vỏ ngọt thanh này là món quà mùa đông đặc trưng từ những ngọn đồi ôn hòa.'),
  'quzhou/cake': ('Bánh nướng Cù Châu', 'Bánh nướng mè giòn rụm được nướng trên thành lò là món ăn sáng truyền thống của người dân địa phương.'),
  'huainan/tofu': ('Cái nôi của đậu phụ', 'Được phát minh tại núi Bát Công cách đây 2.000 năm, đậu phụ từ đây đã lan tỏa ra khắp nền ẩm thực thế giới.'),
  'huainan/coalmine': ('Thành phố than đá', 'Với trữ lượng than dồi dào, Hoài Nam là một trong những trung tâm năng lượng quan trọng của miền Đông Trung Quốc.'),
  'huainan/oldtown': ('Cổ thành Thọ Huyện', 'Tường thành thời Tống được bảo tồn nguyên vẹn là một ví dụ hiếm hoi về thiết kế phòng thủ cổ đại.'),
  'huainan/classic': ('Hoài Nam Tử', 'Tác phẩm triết học kinh điển do Hoài Nam Vương Lưu An biên soạn đã được ra đời trên mảnh đất này.'),
  'jingdezhen/porcelain': ('Thủ phủ gốm sứ', 'Với lịch sử sản xuất gốm sứ hoàng gia suốt ngàn năm, nơi đây được mệnh danh là \'thủ phủ gốm sứ\' của thế giới.'),
  'jingdezhen/kiln': ('Lò gốm cổ', 'Những lò nung hình rồng đốt bằng củi vẫn tiếp tục duy trì nghệ thuật làm gốm truyền thống cho đến ngày nay.'),
  'jingdezhen/bluewhite': ('Gốm sứ thanh hoa', 'Gốm trắng với những họa tiết màu xanh coban là biểu tượng nổi tiếng thế giới của thành phố này.'),
  'jingdezhen/painting': ('Tranh vẽ trên gốm', 'Những tác phẩm gốm được các nghệ nhân bậc thầy vẽ bằng cọ tỉ mỉ được trân trọng như những bức tranh nghệ thuật quý giá.'),
  'jian/jinggang': ('Núi Tỉnh Cương', 'Những ngọn núi mờ sương, nơi đặt căn cứ cách mạng đầu tiên, chính là trái tim của \'du lịch đỏ\'.'),
  'jian/torch': ('Ngọn lửa cách mạng', 'Mảnh đất khởi nguồn cho tư tưởng \'một đốm lửa nhỏ có thể làm cháy cả cánh đồng\' là một di tích lịch sử quan trọng.'),
  'jian/academy': ('Học viện Bạch Lộ Châu', 'Học viện nghìn năm tuổi nằm trên một hòn đảo giữa sông Cám này từng là nơi đào tạo vô số bậc hiền tài thời phong kiến.'),
  'jian/pine': ('Thông Tỉnh Cương', 'Những cây thông đỏ vươn mình trong sương sớm tượng trưng cho tinh thần kiên cường của vùng núi này.'),
  'nanping/wuyi': ('Dãy núi Vũ Di', 'Được UNESCO công nhận là di sản thế giới, dãy núi này là sự kết hợp tuyệt vời giữa cảnh quan thiên nhiên hùng vĩ và giá trị văn hóa lâu đời.'),
  'nanping/rocktea': ('Trà đá Vũ Di', 'Đại Hồng Bào, loại trà ô long mọc trên vách đá, được mệnh danh là một trong những loại trà đắt đỏ nhất thế giới.'),
  'nanping/bambooraft': ('Bè tre Cửu Khúc', 'Du khách có thể trải nghiệm cảm giác ngồi trên bè tre, thả mình trôi theo dòng suối Cửu Khúc uốn lượn giữa những vách đá đỏ.'),
  'nanping/scholar': ('Chu Hy', 'Chu Hy, bậc thầy lỗi lạc và là người sáng lập trường phái Tân Nho giáo, từng dành nhiều năm giảng dạy dưới chân dãy núi này.'),
  'shenzhen/skyscraper': ('Tòa nhà chọc trời', 'Sự trỗi dậy của những tòa nhà chọc trời từ một làng chài nhỏ chỉ trong 40 năm chính là minh chứng cho phép màu kinh tế của Trung Quốc.'),
  'shenzhen/chip': ('Thành phố công nghệ', 'Với chợ điện tử Hoa Cường Bắc và sự hiện diện của nhiều tập đoàn công nghệ lớn, Thâm Quyến được ví như \'Thung lũng Silicon của Trung Quốc\'.'),
  'shenzhen/miniature': ('Cửa sổ thế giới', 'Công viên chủ đề này là biểu tượng của thành phố, nơi quy tụ các mô hình thu nhỏ của những địa danh nổi tiếng trên toàn cầu.'),
  'shenzhen/mangrove': ('Vịnh Thâm Quyến', 'Vùng vịnh với những rặng đước xanh mát này là nơi trú ngụ lý tưởng của các loài chim di cư và cò trắng.'),
  'xian/terracotta': ('Đội quân đất nung', 'Hàng ngàn tượng binh lính bằng đất nung canh giữ lăng mộ Tần Thủy Hoàng được coi là kỳ quan thứ tám của thế giới.'),
  'xian/citywall': ('Tường thành Tây An', 'Đây là bức tường thành thời nhà Minh được bảo tồn nguyên vẹn nhất Trung Quốc, nơi du khách có thể đạp xe dạo quanh trên đỉnh thành.'),
  'xian/drumtower': ('Tháp Chuông', 'Tòa tháp chuông từ thời nhà Minh nằm ngay trung tâm thành phố, đánh dấu trái tim của cố đô Tây An cổ kính.'),
  'xian/roujiamo': ('Nhục giáp mô', 'Với lớp vỏ bánh giòn rụm kẹp thịt hầm đậm đà, nhục giáp mô được coi là phiên bản \'burger\' nguyên bản của Con đường Tơ lụa.'),
  'suzhou/garden': ('Viên lâm Tô Châu', 'Những khu vườn cổ điển với thiết kế tinh xảo gồm non bộ, hồ nước và đình đài này đã được UNESCO vinh danh là di sản thế giới.'),
  'suzhou/watertown': ('Thị trấn nước', 'Với hệ thống kênh rạch chằng chịt, cầu đá cổ và những ngôi nhà trắng, Tô Châu được mệnh danh là \'Venice của phương Đông\'.'),
  'suzhou/embroidery': ('Tô Tú', 'Nghệ thuật thêu lụa hai mặt tinh xảo là một trong những di sản thủ công truyền thống lâu đời nhất của vùng Tô Châu.'),
  'suzhou/kunqu': ('Côn khúc', 'Được coi là cái nôi của các loại hình hí kịch Trung Hoa, Côn khúc thanh tao đã ra đời tại chính nơi đây.'),
  'kunming/stoneforest': ('Thạch Lâm', 'Những cột đá vôi khổng lồ được thiên nhiên chạm khắc qua hàng triệu năm tạo nên một mê cung đá kỳ ảo.'),
  'kunming/springcity': ('Thành phố mùa xuân', 'Với khí hậu ôn hòa quanh năm, Côn Minh được mệnh danh là \'thành phố mùa xuân\' nơi hoa nở không bao giờ tàn.'),
  'kunming/seagull': ('Mòng biển đầu đen', 'Mỗi độ đông về, hàng ngàn chú mòng biển từ Siberia lại bay đến khiến bờ hồ trắng xóa một góc trời.'),
  'kunming/ricenoodle': ('Bún qua cầu', 'Món bún gạo sợi mảnh ăn kèm nước dùng nóng hổi tại bàn chính là đặc sản trứ danh của Vân Nam.'),
  'jinan/spring': ('Thành phố suối', 'Tế Nam được gọi là \'thành phố suối\' nhờ có 72 con suối nổi tiếng phun trào từ lòng đất.'),
  'jinan/daminglake': ('Hồ Đại Minh', 'Được bao quanh bởi những rặng liễu và hoa sen, hồ nước này được nuôi dưỡng bởi chính nguồn nước từ các con suối trong thành phố.'),
  'jinan/buddhamountain': ('Núi Thiên Phật', 'Với hàng trăm bức tượng Phật được chạm khắc trên các sườn núi, đây là địa điểm hành hương linh thiêng của nhiều người.'),
  'jinan/poet': ('Nữ sĩ Lý Thanh Chiếu', 'Lý Thanh Chiếu, nữ thi sĩ vĩ đại nhất lịch sử Trung Quốc, đã sinh ra tại thành phố suối xinh đẹp này.'),
  'ningbo/library': ('Thiên Nhất Các', 'Với lịch sử 450 năm, Thiên Nhất Các là thư viện tư nhân lâu đời nhất còn tồn tại ở châu Á.'),
  'ningbo/port': ('Cảng Ninh Ba - Chu Sơn', 'Cảng Ninh Ba - Chu Sơn hiện là cảng biển bận rộn nhất thế giới tính theo tổng lưu lượng hàng hóa.'),
  'ningbo/tangyuan': ('Thang viên', 'Những viên bánh trôi nhân mè đen ngọt ngào, hay còn gọi là \'thang viên\', là món ăn đặc trưng của thành phố này.'),
  'ningbo/seafood': ('Hải sản', 'Cá đù vàng và cua từ vùng biển Hoa Đông là những nguyên liệu chủ đạo trong ẩm thực địa phương.'),
  'shijiazhuang/bridge': ('Cầu Triệu Châu', 'Cây cầu vòm đá 1.400 năm tuổi này là cây cầu vòm hở cổ nhất thế giới.'),
  'shijiazhuang/clifftemple': ('Núi Thương Nham', 'Ngôi chùa nằm vắt vẻo giữa các vách đá này từng là bối cảnh của vô số bộ phim nổi tiếng.'),
  'shijiazhuang/redbase': ('Khu di tích Tây Bách Pha', 'Đây là ngôi làng nơi kế hoạch xây dựng nước Trung Hoa mới được vạch ra và là điểm đến thiêng liêng của du lịch đỏ.'),
  'shijiazhuang/pharma': ('Thành phố Dược phẩm', 'Là một trong những trung tâm sản xuất dược phẩm lớn nhất Trung Quốc, thành phố này đóng vai trò chủ chốt trong ngành công nghiệp kháng sinh.'),
  'taiyuan/jincitemple': ('Chùa Tấn Từ', 'Với những bức tượng và dòng suối có lịch sử ba nghìn năm, Tấn Từ là ngôi chùa vườn duyên dáng nhất miền Bắc Trung Quốc.'),
  'taiyuan/coalcart': ('Thủ phủ Than đá', 'Các mỏ than của Sơn Tây cung cấp năng lượng cho cả Trung Quốc và Thái Nguyên chính là trung tâm của nguồn tài nguyên giàu có này.'),
  'taiyuan/vinegar': ('Giấm lão trần', 'Giấm lão trần là loại gia vị tạo nên vị chua đặc trưng không thể thiếu trong ẩm thực Sơn Tây.'),
  'taiyuan/twinpagoda': ('Song Tháp', 'Hai ngôi chùa bát giác từ thời nhà Minh đứng cạnh nhau đã trở thành biểu tượng đặc trưng của thành phố.'),
  'hohhot/lamatemple': ('Chùa Đại Chiêu', 'Nổi tiếng với tượng Phật bạc, ngôi chùa Phật giáo Tây Tạng này được coi là trái tim tâm linh của thành phố.'),
  'hohhot/dairy': ('Thủ phủ Sữa', 'Nơi đây là cái nôi của những thương hiệu sữa lớn nhất Trung Quốc, vì vậy thành phố còn được mệnh danh là \'thủ phủ sữa\'.'),
  'hohhot/wrestling': ('Đấu vật Mông Cổ', 'Đấu vật Bökh là điểm nhấn trong lễ hội Naadam, thể hiện sức mạnh phi thường của những người con thảo nguyên.'),
  'hohhot/prairie': ('Thảo nguyên', 'Trải dài bên ngoài thành phố là những thảo nguyên Mông Cổ xanh mướt, nơi có những đàn ngựa và gia súc tung tăng gặm cỏ.'),
  'sanya/resortbeach': ('Bãi biển nhiệt đới', 'Với bãi cát trắng mịn và làn nước xanh ngọc, vịnh Á Long được ví như \'Hawaii của Trung Quốc\'.'),
  'sanya/guanyin': ('Tượng Quan Âm', 'Với chiều cao 108 mét vươn lên trên mặt biển, đây là một trong những bức tượng nữ thần cao nhất thế giới.'),
  'sanya/diving': ('Lặn biển', 'Sở hữu làn nước ấm áp, trong vắt cùng những rạn san hô rực rỡ, Tam Á chính là thiên đường lặn biển của Trung Quốc.'),
  'sanya/coconutdrink': ('Dừa', 'Nước dừa tươi từ những rặng dừa nhiệt đới là thức uống giải khát mát lành đặc trưng của hòn đảo này.'),
  'yangzhou/slenderlake': ('Sấu Tây Hồ', 'Với những hàng liễu rủ và cây cầu trắng, Sấu Tây Hồ mang vẻ đẹp thanh tao tựa như một bức tranh thủy mặc.'),
  'yangzhou/friedrice': ('Cơm chiên Dương Châu', 'Món cơm vàng óng kết hợp cùng tôm và trứng này là một đặc sản nổi tiếng thế giới.'),
  'yangzhou/morningtea': ('Trà sáng', 'Thưởng thức bữa sáng thanh tao với các loại bánh bao và trà là một nghi thức đặc trưng của người Dương Châu.'),
  'yangzhou/gegarden': ('Cá Viên', 'Khu vườn trúc với những hòn non bộ mô phỏng bốn mùa này là một kiệt tác của nghệ thuật thiết kế cổ điển.'),
  'weihai/navalisland': ('Đảo Lưu Công', 'Từng là căn cứ của Hạm đội Bắc Dương, hòn đảo này là nhân chứng lịch sử cho sự phát triển hải quân của Trung Quốc hiện đại.'),
  'weihai/swan': ('Hồ Thiên Nga', 'Mỗi độ đông về, hàng trăm chú thiên nga từ Siberia lại bay về cư ngụ tại đầm phá ven biển này.'),
  'weihai/seacucumber': ('Hải sâm', 'Được nuôi dưỡng trong làn nước biển lạnh và sạch, hải sâm là loại hải sản quý giá nhất của thành phố này.'),
  'weihai/cape': ('Mũi đất Trung Quốc', 'Đây là mũi đất cực đông của Trung Quốc, nơi ánh mặt trời đầu tiên chiếu rọi xuống đất nước.'),
  'handan/taichi': ('Thái Cực Quyền', 'Thành cổ Quảng Phủ, nơi khai sinh ra phái Dương gia và Võ gia, chính là cái nôi của môn Thái Cực Quyền.'),
  'handan/congtai': ('Đài Tùng Đài', 'Đài đất cổ từ thời nước Triệu này đã chứng kiến hơn 2.000 năm lịch sử thăng trầm.'),
  'handan/idiom': ('Thành phố Thành ngữ', 'Với hơn 1.500 câu thành ngữ bắt nguồn từ đây, Hàm Đan được mệnh danh là \'thành phố thành ngữ\'.'),
  'handan/ciporcelain': ('Gốm Từ Châu', 'Gốm Từ Châu với họa tiết đen trên nền trắng là một dòng gốm dân gian kinh điển.'),
  'daqing/oilpump': ('Mỏ dầu', 'Mỏ dầu lớn nhất Trung Quốc này nổi bật với những chiếc máy bơm dầu hoạt động không ngừng nghỉ.'),
  'daqing/oilworker': ('Người sắt', 'Tinh thần kiên cường của người anh hùng công nhân dầu khí Vương Tiến Hỷ chính là linh hồn khai phá của thành phố này.'),
  'daqing/reedlake': ('Đất ngập nước', 'Những hồ sậy rộng lớn nằm xen kẽ giữa các giếng dầu là nơi trú ngụ của nhiều loài sếu và thiên nga.'),
  'daqing/hotspring': ('Suối nước nóng', 'Nguồn nước khoáng nóng từ lòng đất mang đến sự thư giãn tuyệt vời giữa cái lạnh của vùng phương Bắc.'),
  'zibo/bbq': ('Đồ nướng Truy Bác', 'Thịt xiên nướng trên bếp than nhỏ rồi cuốn trong bánh tráng mỏng là trào lưu ẩm thực đã gây sốt khắp cả nước.'),
  'zibo/cuju': ('Xúc cúc', 'Xúc cúc, hình thức sơ khai nhất của môn bóng đá trên thế giới, từng được chơi tại Lâm Truy, kinh đô cổ của nước Tề.'),
  'zibo/ceramic': ('Gốm sứ Truy Bác', 'Với những lò nung có lịch sử hàng nghìn năm, thành phố này là trung tâm sản xuất gốm sứ quan trọng của miền Bắc Trung Quốc.'),
  'zibo/glass': ('Lưu ly', 'Lưu ly là một loại hình thủ công mỹ nghệ được chế tác từ thủy tinh nóng chảy, mang vẻ đẹp lung linh đầy màu sắc.'),
  'taian/mounttai': ('Núi Thái Sơn', 'Là ngọn núi đứng đầu trong Ngũ Nhạc, Thái Sơn được coi là đỉnh núi linh thiêng nhất nơi các hoàng đế xưa thường làm lễ tế trời.'),
  'taian/sunrise': ('Ngắm bình minh trên đỉnh núi', 'Chiêm ngưỡng cảnh mặt trời mọc trên biển mây là phần thưởng xứng đáng nhất cho hành trình leo núi Thái Sơn.'),
  'taian/stonesteps': ('Đường bậc thang đá', 'Hành trình chinh phục 7.000 bậc thang đá dẫn lên đỉnh núi chính là thử thách thể lực đầy cam go của những người hành hương.'),
  'taian/daitemple': ('Đại Miếu', 'Ngôi đền nguy nga nằm dưới chân núi là nơi các hoàng đế xưa chuẩn bị nghi lễ tế lễ tại Thái Sơn.'),
  'lianyungang/monkey': ('Hoa Quả Sơn', 'Hoa Quả Sơn, quê hương của Tôn Ngộ Không trong tác phẩm \'Tây Du Ký\', tọa lạc ngay tại nơi đây.'),
  'lianyungang/seaport': ('Cảng biển Liên Vân Cảng', 'Đây là cửa ngõ biển phía đông của Con đường Tơ lụa và là điểm cuối phía Thái Bình Dương của cây cầu đường sắt Á-Âu.'),
  'lianyungang/mountain': ('Núi Vân Đài', 'Với những đỉnh núi dốc đứng và rừng cây xanh mướt, Vân Đài là ngọn núi cao nhất tại tỉnh Giang Tô.'),
  'lianyungang/crystal': ('Thủ phủ pha lê', 'Khu vực Đông Hải lân cận là nơi tập trung một trong những thị trường pha lê thạch anh lớn nhất thế giới.'),
  'maanshan/libai': ('Thi tiên Lý Bạch', 'Thành phố ven sông này là nơi an nghỉ cuối cùng của Lý Bạch, nhà thơ vĩ đại nhất trong lịch sử Trung Quốc.'),
  'maanshan/steel': ('Thành phố thép', 'Nhà máy thép Mã Cương đã biến nơi đây trở thành một trong những cơ sở công nghiệp luyện kim trọng điểm của Trung Quốc.'),
  'maanshan/rivercliff': ('Thái Thạch Cơ', 'Vách đá hùng vĩ đổ xuống dòng Trường Giang này chính là bối cảnh thơ mộng gắn liền với truyền thuyết về thi tiên Lý Bạch.'),
  'maanshan/moonwine': ('Trăng và Rượu', 'Vẻ đẹp của trăng và rượu trong thơ Lý Bạch vẫn được người dân tôn vinh qua các lễ hội bên bờ sông.'),
  'longyan/tulou': ('Thổ lâu Vĩnh Định', 'Những pháo đài nhà ở hình tròn khổng lồ của người Khách Gia nằm rải rác trên các ngọn đồi đã được UNESCO công nhận là di sản thế giới.'),
  'longyan/redmeeting': ('Hội nghị Cổ Điền', 'Đây là nơi diễn ra hội nghị lịch sử định hình con đường phát triển của Hồng quân Trung Quốc.'),
  'longyan/hakka': ('Văn hóa Khách Gia', 'Người Khách Gia, những người di cư từ phương Bắc, vẫn lưu giữ ngôn ngữ và ẩm thực độc đáo của mình giữa những ngọn đồi này.'),
  'longyan/mountain': ('Núi Quan Trại', 'Với những vách đá đỏ và hồ nước trong vắt, ngọn núi này được coi là viên ngọc tự nhiên của vùng nam Phúc Kiến.'),
  'sanming/danxia': ('Đan Hà Thái Ninh', 'Với những vách đá đỏ và hẻm núi hùng vĩ, công viên địa chất UNESCO này tựa như một mê cung đá rơi xuống từ thiên đường.'),
  'sanming/shaxian': ('Đồ ăn vặt Sa Huyện', 'Với món hoành thánh và mì trộn giá rẻ, đồ ăn vặt Sa Huyện đã trở nên phổ biến trên khắp Trung Quốc.'),
  'sanming/forest': ('Thủ phủ Xanh', 'Là thành phố có độ che phủ rừng lớn nhất Trung Quốc, Tam Minh sở hữu bầu không khí trong lành và những ngọn núi xanh mướt.'),
  'sanming/goldenlake': ('Hồ Kim', 'Trải dài giữa những vách đá Đan Hà, hồ nước này là điểm đến lý tưởng để du khách khám phá bằng thuyền.'),
  'ningde/mudflat': ('Bãi bùn Hà Phố', 'Những bãi triều lấp lánh thay đổi theo con nước là một trong những bờ biển được chụp ảnh nhiều nhất trên thế giới.'),
  'ningde/whitetea': ('Bạch trà Phúc Đỉnh', 'Được làm từ những búp trà phủ lông tơ, bạch trà càng để lâu càng trở nên quý giá.'),
  'ningde/taimu': ('Núi Thái Mỗ', 'Với những đỉnh đá granite và hang động hướng ra biển, ngọn núi này được mệnh danh là \'tiên cảnh giữa biển khơi\'.'),
  'ningde/croaker': ('Cá đù vàng', 'Cá đù vàng được nuôi trong các vịnh kín gió là báu vật biển cả của thành phố này.'),
  'shaoguan/redcliff': ('Núi Đan Hà', 'Ngọn núi đá đỏ đặt tên cho địa hình \'Đan Hà\' nổi tiếng với những cột đá tự nhiên kỳ vĩ.'),
  'shaoguan/chantemple': ('Chùa Nam Hoa', 'Đây là ngôi chùa của Huệ Năng, Lục tổ Thiền tông, và là trung tâm linh thiêng của phái này.'),
  'shaoguan/ancestor': ('Ngõ Châu Cơ', 'Đây là nơi khởi nguồn của hàng triệu người Hoa phương Nam, những người luôn tìm về cội nguồn tổ tiên mình.'),
  'shaoguan/yaodance': ('Người Dao', 'Người dân tộc Dao sống ở các bản làng miền núi nổi tiếng với trang phục rực rỡ và những điệu múa trống đặc sắc.'),
  'zhanjiang/oyster': ('Hàu Trạm Giang', 'Những con hàu béo ngậy từ vùng biển ấm phương Nam được nướng trên than hồng tạo nên món ăn vô cùng hấp dẫn.'),
  'zhanjiang/navy': ('Cảng Hải quân', 'Là căn cứ của Hạm đội Nam Hải, cảng nước sâu này được coi là cửa ngõ biển phía Nam của quốc gia.'),
  'zhanjiang/mangrove': ('Rừng ngập mặn', 'Khu rừng ngập mặn lớn nhất Trung Quốc này là nơi trú ngụ của nhiều loài cò và cua trong vùng nước thủy triều.'),
  'zhanjiang/donghai': ('Đảo Đông Hải', 'Với bãi biển dài và gió lộng, hòn đảo này là điểm đến lý tưởng cho những ai yêu thích tắm nắng và lướt sóng.'),
  'maoming/lychee': ('Thủ phủ vải thiều', 'Mậu Danh là vùng sản xuất vải thiều lớn nhất Trung Quốc, nơi từng cung tiến loại quả này cho các bậc hoàng đế xưa.'),
  'maoming/refinery': ('Cơ sở hóa dầu', 'Một trong những nhà máy lọc dầu lớn nhất miền Nam Trung Quốc là động lực thúc đẩy sức mạnh công nghiệp của thành phố.'),
  'maoming/ladyxian': ('Phu nhân Tiển', 'Phu nhân Tiển, nữ anh hùng có công thống nhất phương Nam, đã được người dân tôn kính suốt hàng ngàn năm qua.'),
  'maoming/seaside': ('Bãi biển', 'Được mệnh danh là \'Bãi biển số 1 Trung Quốc\', bờ biển dài này mang đến cho các gia đình những bãi cát vàng tuyệt đẹp.'),
  'zhaoqing/sevenstar': ('Thất Tinh Nham', 'Bảy ngọn núi đá vôi nhô lên từ mặt hồ được ví như \'Quế Lâm của Quảng Đông\'.'),
  'zhaoqing/inkstone': ('Nghiên mực Đoan Khê', 'Nghiên mực Đoan Khê, một trong bốn báu vật của nghệ thuật thư pháp, đã được chế tác tại đây suốt hàng ngàn năm.'),
  'zhaoqing/dinghu': ('Núi Đỉnh Hồ', 'Khu bảo tồn thiên nhiên đầu tiên của Trung Quốc với rừng mưa nhiệt đới và thác nước hùng vĩ được ví như một \'phòng oxy\' tự nhiên.'),
  'zhaoqing/songwall': ('Tường thành thời Tống', 'Bức tường thành thời Tống được bảo tồn nguyên vẹn bao quanh thành phố Triệu Khánh cổ kính, lưu giữ dấu ấn lịch sử lâu đời.'),
  'huizhou/westlake': ('Tây Hồ Huệ Châu', 'Từng được thi hào Tô Thức yêu mến, hồ nước này đẹp tựa một bài thơ với những hàng liễu rủ và những con đường đắp cao.'),
  'huizhou/luofu': ('Núi La Phù', 'Được mệnh danh là một trong những ngọn núi thiêng nhất phương Nam, đây là nơi ẩn cư của các đạo sĩ và là vùng đất của nhiều loại thảo dược quý.'),
  'huizhou/alchemy': ('Lò luyện đan của Cát Hồng', 'Nhà giả kim kiêm danh y Cát Hồng đã viết nên những nền tảng quan trọng của y học cổ truyền khi tu luyện tại ngọn núi này.'),
  'huizhou/xunliao': ('Vịnh Huân Liêu', 'Với làn nước trong xanh và bãi cát mịn màng, vịnh biển này là điểm nghỉ dưỡng yên bình bậc nhất ở vùng duyên hải phía Nam.'),
  'meizhou/weilongwu': ('Nhà围龙屋 (Vi Long Ốc)', 'Được mệnh danh là \'thủ phủ người Khách Gia\', Mai Châu nổi tiếng với những ngôi nhà Vi Long Ốc có kiến trúc hình móng ngựa độc đáo.'),
  'meizhou/saltchicken': ('Gà hấp muối', 'Gà hấp muối là món đặc sản trứ danh của người Khách Gia với phần thịt mềm ngọt nhờ phương pháp chế biến vùi trong muối nóng.'),
  'meizhou/football': ('Cái nôi bóng đá', 'Được coi là cái nôi của bóng đá Trung Quốc, thành phố này đã đào tạo ra nhiều thế hệ cầu thủ ngôi sao cho đất nước.'),
  'meizhou/plum': ('Hoa mai', 'Đúng như tên gọi \'Mai Châu\', thành phố này được tô điểm bởi sắc hoa mai rực rỡ mỗi độ đông về.'),
  'jiangmen/diaolou': ('Nhà chòi Khai Bình', 'Những tòa tháp pháo đài nhiều tầng do người Hoa di cư xây dựng đã được UNESCO công nhận là di sản thế giới.'),
  'jiangmen/qiaoxiang': ('Quê hương của người Hoa hải ngoại', 'Là quê hương của hàng triệu người Hoa sinh sống ở nước ngoài, nơi đây mang đậm nét giao thoa văn hóa giữa phương Đông và phương Tây.'),
  'jiangmen/chenpi': ('Trần bì', 'Vỏ quýt Tân Hội lâu năm không chỉ là một loại gia vị đặc biệt mà còn là vị thuốc quý giá.'),
  'jiangmen/birds': ('Thiên đường chim', 'Một khu rừng được hình thành từ duy nhất một cây đa cổ thụ khổng lồ, là nơi cư ngụ của hàng vạn con cò.'),
  'yangjiang/knife': ('Thủ phủ dao kéo', 'Phần lớn dao làm bếp của Trung Quốc được rèn tại đây nhờ truyền thống chế tác kim khí có lịch sử hàng trăm năm.'),
  'yangjiang/shipwreck': ('Tàu Nam Hải số 1', 'Con tàu thời nhà Tống từ Con đường Tơ lụa trên biển được trưng bày cùng với kho báu bên trong tại một bảo tàng dưới nước độc đáo.'),
  'yangjiang/hailing': ('Đảo Hải Lăng', 'Với những bãi biển đầy nắng và sóng vỗ, hòn đảo này là điểm du lịch nghỉ dưỡng ven biển được yêu thích nhất tại Quảng Đông.'),
  'yangjiang/kite': ('Thành phố diều', 'Cùng với Duy Phường, đây là một trong hai \'thủ phủ diều\' của Trung Quốc, nơi những cánh diều rợp trời mỗi độ thu sang.'),
  'qingyuan/rafting': ('Thủ phủ chèo thuyền vượt thác', 'Với những dòng suối chảy xiết từ núi cao, Thanh Viễn được mệnh danh là quê hương của bộ môn chèo thuyền vượt thác tại Trung Quốc.'),
  'qingyuan/chicken': ('Gà Thanh Viễn', 'Giống gà địa phương với xương nhỏ và thịt thơm ngon này là món ăn được săn đón nhất trên bàn tiệc của người Quảng Đông.'),
  'qingyuan/hotspring': ('Suối nước nóng', 'Những dòng suối khoáng nóng từ các thung lũng núi là điểm đến lý tưởng cho các chuyến nghỉ dưỡng cuối tuần.'),
  'qingyuan/yaoterrace': ('Ruộng bậc thang người Dao', 'Những thửa ruộng bậc thang được người Dao ở Liên Nam khai phá trên sườn núi là minh chứng cho hàng thế kỷ lao động miệt mài.'),
  'chaozhou/guangjibridge': ('Cầu Quảng Tế', 'Cây cầu cổ có thể đóng mở để tàu thuyền qua lại ở giữa này là một trong bốn cây cầu nổi tiếng nhất Trung Quốc.'),
  'chaozhou/woodcarving': ('Điêu khắc gỗ dát vàng', 'Những tác phẩm điêu khắc gỗ nhiều tầng được dát vàng lá tạo nên vẻ đẹp lộng lẫy cho các ngôi đền.'),
  'chaozhou/chaoxiu': ('Thêu Triều Châu', 'Với kỹ thuật thêu chỉ vàng nổi, thêu Triều Châu được coi là phong cách thêu thùa xa hoa bậc nhất miền Nam Trung Quốc.'),
  'chaozhou/kaiyuan': ('Chùa Khai Nguyên', 'Ngôi chùa 1.200 năm tuổi với những khoảng sân tĩnh lặng mang phong cách thời Đường này chính là trái tim của thành phố.'),
  'jieyang/citygate': ('Cổng Tấn Hiền', 'Tòa tháp gỗ duyên dáng bắc qua sông này là biểu tượng còn sót lại của thành phố Yết Dương xưa.'),
  'jieyang/jade': ('Thủ phủ ngọc bích', 'Thị trấn Dương Mỹ là một trong những trung tâm chế tác và giao dịch ngọc bích lớn nhất Trung Quốc.'),
  'jieyang/jieyanglou': ('Tháp Yết Dương', 'Tòa tháp khổng lồ với mái hiên truyền thống này là một công trình hiện đại tôn vinh văn hóa Triều Sán.'),
  'jieyang/beefbroth': ('Lẩu bò Triều Sán', 'Thịt bò tươi chần qua nước dùng trong là món ăn trứ danh của vùng đất này.'),
  'yunfu/marble': ('Vương quốc đá', 'Là thủ phủ của ngành chế tác đá và đá cẩm thạch, Vân Phù xuất khẩu các sản phẩm đá mài bóng đi khắp thế giới.'),
  'yunfu/patriarch': ('Lục tổ Huệ Năng', 'Là quê hương của Thiền sư Huệ Năng, vùng đất này trở nên linh thiêng nhờ sự hiện diện của chùa Quốc Ân.'),
  'yunfu/tianlu': ('Núi Thiên Lộ', 'Với những đỉnh núi chạm mây và các đồi chè xanh mướt, ngọn núi này được ví như chiếc vương miện xanh của thành phố.'),
  'yunfu/xijiang': ('Tây Giang', 'Là nhánh chính của sông Châu Giang, dòng thủy lộ lớn của phương Nam này chảy ngang qua thành phố.'),
  'liuzhou/luosifen': ('Bún ốc Liễu Châu', 'Món bún ốc có hương vị chua cay nồng đặc trưng đang trở thành cơn sốt ẩm thực trên khắp Trung Quốc.'),
  'liuzhou/autocity': ('Thành phố ô tô', 'Với những mẫu xe cỡ nhỏ được ưa chuộng, Liễu Châu hiện là một trong những trung tâm sản xuất ô tô lớn nhất Trung Quốc.'),
  'liuzhou/karst': ('Địa hình karst sông Liễu', 'Những ngọn núi đá vôi cùng khúc quanh của dòng sông bao bọc lấy thành phố đã tạo nên vẻ đẹp thiên nhiên cho vùng đất công nghiệp này.'),
  'liuzhou/liuhou': ('Thi hào Liễu Tông Nguyên', 'Ký ức về vị thi hào kiêm thái thú thời nhà Đường, Liễu Tông Nguyên, vẫn được lưu giữ tại ngôi đền trong công viên thành phố.'),
  'wuzhou/gemstone': ('Thủ phủ đá quý', 'Phần lớn đá quý nhân tạo trên thế giới đều được chế tác tại các xưởng thủ công ở thành phố ven sông này.'),
  'wuzhou/liubaotea': ('Trà đen Lục Bảo', 'Trà đen Lục Bảo ủ lâu năm là thức uống truyền thống giúp hỗ trợ tiêu hóa rất phổ biến ở vùng phương Nam nóng ẩm.'),
  'wuzhou/turtlejelly': ('Quy linh cao', 'Món thạch thảo mộc màu đen có vị đắng nhẹ này là món ăn giải nhiệt lý tưởng trong những ngày nắng nóng.'),
  'wuzhou/dragonmother': ('Đền Long Mẫu', 'Được xây dựng để thờ phụng nữ thần sông Long Mẫu, ngôi đền là nơi gửi gắm đức tin lâu đời của người dân vùng sông nước.'),
  'beihai/silverbeach': ('Bãi biển Ngân Than', 'Với bãi cát mịn lấp lánh, nơi đây được mệnh danh là \'bãi biển số một dưới gầm trời\' trải dài hàng dặm.'),
  'beihai/pearl': ('Thành phố ngọc trai', 'Ngọc trai biển Nam ở Hợp Phố từ lâu đã được coi là loại trân châu thượng hạng nhất kể từ thời kỳ cống nạp cho hoàng đế.'),
  'beihai/weizhou': ('Đảo Vi Châu', 'Hòn đảo núi lửa trẻ nhất Trung Quốc này thu hút thợ lặn bởi những vách đá đen huyền bí và các rạn san hô rực rỡ.'),
  'beihai/oldstreet': ('Phố cổ', 'Những tòa nhà kiến trúc thuộc địa có hàng hiên trăm năm tuổi vẫn lưu giữ dấu ấn quá khứ của cảng biển trên Con đường Tơ lụa trên biển.'),
  'qinzhou/nixingpottery': ('Gốm Nê Hưng', 'Gốm Nê Hưng, loại gốm có khả năng tự thay đổi màu sắc trong lò nung, là một trong bốn loại gốm sứ nổi tiếng nhất Trung Quốc.'),
  'qinzhou/dolphin': ('Cá heo trắng', 'Loài cá heo trắng Trung Quốc quý hiếm bơi lội ở vịnh Tam Nương chính là biểu tượng đáng tự hào của thành phố.'),
  'qinzhou/oysterfarm': ('Trại hàu', 'Những con hàu khổng lồ được nuôi tại các vịnh nông đã biến Khâm Châu thành thủ phủ hàu của Trung Quốc.'),
  'qinzhou/general': ('Tướng quân Phùng Tử Tài', 'Đây là quê hương của vị tướng già Phùng Tử Tài, người từng trấn giữ biên cương với những dấu ấn hào hùng.'),
  'guigang/lotus': ('Thành phố hoa sen', 'Với những đầm sen rộng lớn nở rộ suốt mùa hè, Quý Cảng được mệnh danh là \'thành phố hoa sen\'.'),
  'guigang/uprising': ('Khởi nghĩa Kim Điền', 'Ngọn lửa đầu tiên của cuộc khởi nghĩa Thái Bình Thiên Quốc chấn động lịch sử đã được thắp lên trên mảnh đất này.'),
  'guigang/nanshan': ('Chùa Nam Sơn', 'Ngôi chùa hang nghìn năm tuổi được chạm khắc vào vách đá này còn lưu giữ nhiều bút tích của hoàng đế.'),
  'guigang/sugarcane': ('Mía đường', 'Đồng bằng ven sông màu mỡ chính là nguồn cung cấp nguyên liệu ngọt ngào cho ngành sản xuất đường lớn nhất Trung Quốc.'),
  'yulin/medicine': ('Chợ dược liệu', 'Đây là chợ thuốc đông y lớn nhất miền Nam Trung Quốc, nơi tập trung hàng nghìn loại thảo dược quý.'),
  'yulin/goldenpalace': ('Vân Thiên Cung', 'Cung điện văn hóa khổng lồ dát vàng này khiến du khách choáng ngợp bởi những bức tượng và đại sảnh nguy nga.'),
  'yulin/lychee': ('Vườn vải', 'Những trái vải ngọt lịm trồng trên các sườn đồi ấm áp là báu vật đỏ rực của các khu chợ mùa hè.'),
  'yulin/beef': ('Thịt bò Ngọc Lâm', 'Món thịt bò khô tẩm gia vị là món ăn vặt đặc sản lâu đời của vùng đất này.'),
  'baise/redbase': ('Khởi nghĩa Bách Sắc', 'Cuộc khởi nghĩa do Đặng Tiểu Bình lãnh đạo khi còn trẻ là bước ngoặt quan trọng trong lịch sử cách mạng.'),
  'baise/sinkhole': ('Hố sụt Lạc Nghiệp', 'Cụm hố sụt khổng lồ lớn nhất thế giới này ẩn chứa những khu rừng nguyên sinh kỳ bí dưới đáy sâu.'),
  'baise/mango': ('Thủ phủ xoài', 'Nhờ những thung lũng nóng ẩm, Bách Sắc trở thành nơi sở hữu những vườn xoài lớn nhất Trung Quốc.'),
  'baise/aluminum': ('Thành phố nhôm', 'Với trữ lượng quặng bô-xít dồi dào, thành phố này là cơ sở công nghiệp nhôm quan trọng ở miền Nam Trung Quốc.'),
  'hechi/longevity': ('Ba Mã trường thọ', 'Với nhiều cư dân sống qua trăm tuổi, Ba Mã là \'quê hương trường thọ\' nổi tiếng thế giới.'),
  'hechi/folksong': ('Lưu Tam Tỷ', 'Huyền thoại về nàng tiên hát Lưu Tam Tỷ vẫn được lưu truyền qua các cuộc thi hát đối đáp dân gian.'),
  'hechi/bronzedrum': ('Trống đồng', 'Đây là nơi lưu giữ mật độ trống đồng linh thiêng của người Choang và các dân tộc vùng cao lớn nhất.'),
  'hechi/geopark': ('Công viên địa chất Karst', 'Với hệ thống hố sụt, hang động và sông ngầm, khu vực này là một kỳ quan địa chất đá vôi thực thụ.'),
  'laibin/sugarcity': ('Thủ phủ đường', 'Với những cánh đồng mía bạt ngàn, Lai Tân được mệnh danh là \'thủ phủ đường\' của Trung Quốc.'),
  'laibin/yao': ('Người Dao Đại Dao', 'Người Dao ở vùng núi Đại Dao thuộc Kim Tú với năm nhánh văn hóa đặc trưng là một kho tàng di sản quý báu.'),
  'laibin/hongshui': ('Sông Hồng Thủy', 'Dòng sông Hồng Thủy hùng vĩ chảy qua các thung lũng không chỉ cung cấp thủy điện mà còn tạo nên những cảnh quan tuyệt đẹp.'),
  'laibin/shengtang': ('Núi Thánh Đường', 'Với biển mây và những thác nước hùng vĩ, đây là đỉnh núi cao nhất của dãy Đại Dao.'),
  'chongzuo/waterfall': ('Thác Bản Giốc', 'Nằm trên biên giới Việt - Trung, Bản Giốc là thác nước xuyên quốc gia lớn nhất châu Á.'),
  'chongzuo/langur': ('Voọc đầu trắng', 'Chỉ sinh sống tại các dãy núi đá vôi ở đây, loài voọc đầu trắng quý hiếm là một trong những loài linh trưởng bị đe dọa nhất thế giới.'),
  'chongzuo/rockart': ('Tranh đá Hoa Sơn', 'Những hình vẽ màu đỏ trên vách đá Tả Giang có niên đại 2.000 năm đã được UNESCO công nhận là di sản thế giới.'),
  'chongzuo/borderpass': ('Ải Nam Quan', 'Cửa khẩu biên giới lịch sử nối liền với Việt Nam này từng là cửa ngõ đường bộ quan trọng của Con đường Tơ lụa phương Nam.'),
  'beijing/great-wall': ('Vạn Lý Trường Thành', 'Đây là công trình phòng thủ dài nhất thế giới với hơn 20.000 km được xây dựng qua nhiều thế kỷ để bảo vệ biên giới phía bắc Trung Quốc, trong đó đoạn Bát Đạt Lĩnh gần Bắc Kinh là nơi thu hút nhiều du khách nhất.'),
  'beijing/temple': ('Thiên Đàn', 'Đây là nơi các hoàng đế nhà Minh và nhà Thanh thực hiện nghi lễ tế trời cầu mùa màng bội thu, với kiến trúc mái vòm ba tầng màu xanh không dùng một chiếc đinh nào.'),
  'beijing/pagoda': ('Chùa Thiên Ninh', 'Ngôi chùa gạch 13 tầng cao khoảng 57 mét từ thời nhà Liêu này là một trong những công trình cổ nhất còn sót lại ở Bắc Kinh, chứng nhân cho lịch sử ngàn năm của thành phố.'),
  'beijing/opera': ('Kinh kịch', 'Loại hình nghệ thuật truyền thống 200 năm tuổi này kết hợp giữa hát, thoại, võ thuật và nhào lộn, với các kiểu vẽ mặt (liên phổ) giúp khán giả nhận diện tính cách nhân vật như đỏ là trung thành, trắng là gian xảo.'),
  'zunyi/huiyi': ('Hội nghị Tuân Nghĩa', 'Ngôi nhà diễn ra cuộc họp năm 1935 đã thay đổi vận mệnh cách mạng, trở thành bước ngoặt trong lịch sử đỏ của Trung Quốc.'),
  'zunyi/moutai': ('Thị trấn Mao Đài', 'Được chưng cất tại thị trấn bên bờ sông Xích Thủy, rượu Mao Đài là loại bạch tửu huyền thoại được mệnh danh là quốc tửu của Trung Quốc.'),
  'zunyi/loushan': ('Đèo Lâu Sơn', 'Con đèo hiểm trở cắt ngang dãy núi này là nơi diễn ra trận chiến lịch sử được bất tử hóa trong bài thơ nổi tiếng của Mao Trạch Đông.'),
  'zunyi/chishui': ('Thác Xích Thủy', 'Những dòng thác đổ xuống từ vách đá Đan Hà đỏ rực giữa rừng trúc bạt ngàn tạo nên vẻ đẹp hùng vĩ cho thung lũng sông Xích Thủy.'),
  'liupanshui/coolcity': ('Thành phố Mát mẻ', 'Với nhiệt độ mùa hè hiếm khi vượt quá 19°C, Lục Bàn Thủy được mệnh danh là \'thủ phủ mát mẻ\' của Trung Quốc.'),
  'liupanshui/coal': ('Biển than Tây Nam', 'Trữ lượng than đá phong phú đã biến nơi đây thành trung tâm năng lượng quan trọng của vùng Tây Nam Trung Quốc.'),
  'liupanshui/grassland': ('Đồng cỏ Ô Mông', 'Những đồng cỏ cao nguyên trải dài vô tận trên cao nguyên Ô Mông điểm xuyết bởi các đàn ngựa và những cánh quạt điện gió.'),
  'liupanshui/kiwi': ('Kiwi ruột đỏ', 'Được trồng trên vùng cao nguyên mát mẻ, kiwi ruột đỏ là đặc sản ngọt ngào đầy tự hào của thành phố này.'),
  'anshun/huangguoshu': ('Thác Hoàng Quả Thụ', 'Thác nước lớn nhất châu Á đổ xuống từ độ cao 77 mét, tạo nên màn sương mù rực rỡ sắc cầu vồng.'),
  'anshun/dixi': ('Kịch Địa hí', 'Được biểu diễn tại các quảng trường làng với những chiếc mặt nạ gỗ, Địa hí được coi là \'hóa thạch sống\' của nghệ thuật kịch Trung Hoa.'),
  'anshun/batik': ('Nghệ thuật nhuộm sáp', 'Vải vẽ sáp nhuộm chàm của phụ nữ dân tộc Bố Y và Miêu là nghề thủ công đặc trưng của An Thuận.'),
  'anshun/tunpu': ('Làng Đồn Phố', 'Người dân tại các thị trấn đồn trú bằng đá từ thời nhà Minh vẫn lưu giữ nguyên vẹn trang phục và phương ngữ từ 600 năm trước.'),
  'bijie/azalea': ('Rừng đỗ quyên Bách Lý', 'Biển hoa đỗ quyên bao phủ các sườn núi mỗi độ xuân về là vườn hoa tự nhiên lớn nhất thế giới.'),
  'bijie/zhijin': ('Động Chức Kim', 'Với những rừng măng đá khổng lồ, \'cung điện dưới lòng đất\' Chức Kim là hang động ngoạn mục nhất Trung Quốc.'),
  'bijie/caohai': ('Sếu Thảo Hải', 'Hồ nước nông tại Uy Ninh là nơi trú đông lý tưởng của loài sếu cổ đen quý hiếm.'),
  'bijie/potato': ('Thủ phủ khoai tây', 'Khoai tây vùng cao khiến Tất Tiết trở thành vựa khoai tây của Trung Quốc, trong đó khoai tây Uy Ninh nổi tiếng khắp cả nước.'),
  'qujing/rapeseed': ('Biển hoa cải La Bình', 'Mỗi dịp tháng Hai, những cánh đồng hoa cải vàng rực ở La Bình lại thu hút đông đảo người nuôi ong và các nhiếp ảnh gia.'),
  'qujing/ham': ('Giăm bông Tuyên Uy', 'Với lịch sử muối ướp hàng thế kỷ, giăm bông Tuyên Uy là niềm tự hào trên bàn ăn của người Vân Nam.'),
  'qujing/jiulong': ('Thác Cửu Long', 'Mười tầng thác đổ của dòng sông Cửu Long tạo nên chuỗi thác nước đẹp nhất Trung Quốc.'),
  'qujing/sandforest': ('Rừng cát ngũ sắc', 'Những cột cát đa sắc màu được gió điêu khắc tạo thành một vườn tượng tự nhiên tại Lục Lương.'),
  'yuxi/fuxian': ('Hồ Phủ Tiên', 'Là hồ nước sâu thứ hai tại Trung Quốc, hồ Phủ Tiên tựa như một tấm gương soi trong vắt giữa núi rừng.'),
  'yuxi/nieer': ('Nhạc sĩ Nhiếp Nhĩ', 'Là quê hương của Nhiếp Nhĩ, người soạn nhạc quốc ca, thành phố đã xây dựng công viên âm nhạc và đài tưởng niệm để vinh danh ông.'),
  'yuxi/chengjiang': ('Hóa thạch Trừng Giang', 'Các lớp hóa thạch kỷ Cambri có niên đại 530 triệu năm là di sản UNESCO ghi dấu buổi bình minh của sự sống động vật.'),
  'yuxi/kiln': ('Lò gốm Ngọc Khê', 'Lò gốm cổ từ thời Nguyên là nơi khởi nguồn của dòng gốm xanh trắng Vân Nam.'),
  'dali/threepagodas': ('Sùng Thánh Tự Tam Tháp', 'Đứng sừng sững dưới chân núi Thương Sơn suốt ngàn năm, ba ngôi tháp duyên dáng là biểu tượng của vương quốc Đại Lý cổ xưa.'),
  'dali/erhai': ('Hồ Nhĩ Hải', 'Hồ Nhĩ Hải hình tai người là một bức tranh thủy mặc với những con thuyền đánh cá và các ngôi làng ven hồ.'),
  'dali/cangshan': ('Núi Thương Sơn', 'Với mười chín đỉnh núi quanh năm tuyết phủ, Thương Sơn sừng sững như một bức màn xanh phía sau thành Đại Lý.'),
  'dali/wind': ('Phong Hoa Tuyết Nguyệt', 'Gió Hạ Quan, hoa Thượng Quan, tuyết Thương Sơn và trăng Nhĩ Hải là bốn cảnh đẹp của Đại Lý tựa như một bài thơ.'),
  'lijiang/oldtown': ('Phố cổ Lệ Giang', 'Đan xen giữa những con kênh và những ngôi nhà gỗ mái ngói, phố cổ di sản UNESCO này là trái tim sống động của văn hóa Nạp Tây.'),
  'lijiang/snowmountain': ('Núi tuyết Ngọc Long', 'Đỉnh núi băng giá cao 5.596 mét tỏa sáng trên thị trấn như một con rồng ngọc đang say ngủ.'),
  'lijiang/dongba': ('Chữ tượng hình Đông Ba', 'Chữ Đông Ba của các thầy cúng người Nạp Tây là hệ thống chữ tượng hình sống duy nhất còn tồn tại trên thế giới.'),
  'lijiang/tigerleaping': ('Hẻm núi Hổ Nhảy', 'Hẻm núi Hổ Nhảy gắn liền với truyền thuyết về chú hổ nhảy qua sông, được biết đến là một trong những hẻm núi sâu nhất thế giới.'),
  'lincang/dianhong': ('Trà đen Điền Hồng', 'Loại trà đen búp vàng trứ danh từ Phụng Khánh này đã đưa danh tiếng trà Vân Nam vươn tầm thế giới.'),
  'lincang/wadrum': ('Trống gỗ người Ngõa', 'Tiếng trống gỗ linh thiêng của người Ngõa vang vọng khắp các bản làng trong điệu múa lắc tóc truyền thống.'),
  'lincang/teatrees': ('Cây trà cổ thụ', 'Lâm Thương là nơi lưu giữ những cánh rừng trà cổ thụ hàng nghìn năm tuổi, được coi là cái nôi của cây trà.'),
  'lincang/lancang': ('Sông Lan Thương', 'Là thượng nguồn của sông Mê Kông, sông Lan Thương chảy về phía nam và cung cấp nguồn năng lượng dồi dào nhờ các đập thủy điện khổng lồ.'),
  'puer/tea': ('Trà Phổ Nhĩ', 'Trà Phổ Nhĩ ép bánh với hương vị càng để lâu càng đậm đà là báu vật sống mang tên thành phố này.'),
  'puer/coffee': ('Thủ phủ cà phê Trung Quốc', 'Hơn một nửa sản lượng cà phê của Trung Quốc được trồng trên những sườn đồi mờ sương ở Phổ Nhĩ, nơi không khí luôn thoang thoảng hương cà phê.'),
  'puer/teahorse': ('Trà Mã Cổ Đạo', 'Con đường cổ xưa nơi các đoàn thương buôn vận chuyển trà đến Tây Tạng bắt đầu từ Phổ Nhĩ và vươn mình lên những tầng mây.'),
  'puer/peafowl': ('Công xanh', 'Những cánh rừng nhiệt đới che chở cho loài công xanh quý hiếm chính là niềm tự hào hoang dã của thành phố.'),
  'baoshan/volcano': ('Núi lửa Đằng Xung', 'Chín mươi bảy miệng núi lửa đã tắt biến vùng bình nguyên Đằng Xung thành một cảnh quan kỳ vĩ tựa như bề mặt mặt trăng.'),
  'baoshan/rehai': ('Nhiệt Hải', 'Tại thung lũng Nhiệt Hải, du khách có thể chiêm ngưỡng những mạch nước phun trào và thưởng thức món trứng luộc chín bằng nước khoáng nóng.'),
  'baoshan/heshun': ('Trấn Hòa Thuận', 'Thị trấn đá Hòa Thuận, nơi lưu dấu chân của những thương nhân viễn xứ, hiện vẫn bảo tồn thư viện làng cổ nhất Trung Quốc.'),
  'baoshan/gaoligong': ('Dãy núi Cao Lê Cống', 'Với những thung lũng bướm và rừng nhiệt đới ấm áp, Cao Lê Cống được mệnh danh là kho báu đa dạng sinh học của thiên nhiên.'),
  'deyang/sanxingdui': ('Di chỉ Tam Tinh Đôi', 'Những chiếc mặt nạ đồng khổng lồ với đôi mắt lồi đã làm sáng tỏ nền văn minh Thục cổ đại đầy bí ẩn cách đây 3.000 năm.'),
  'deyang/jiannanchun': ('Rượu Kiếm Nam Xuân', 'Kiếm Nam Xuân là loại bạch tửu từ Miên Trúc từng được tiến cung thời nhà Đường và có lịch sử chưng cất suốt mười lăm thế kỷ.'),
  'deyang/nianhua': ('Tranh Tết Miên Trúc', 'Những bức tranh Tết in mộc bản vẽ tay mang đến sắc màu và vận may cho mỗi gia đình khi treo trước cửa.'),
  'deyang/turbine': ('Thủ phủ công nghiệp nặng', 'Phần lớn các loại tuabin và máy phát điện khổng lồ của quốc gia đều được chế tạo tại các xưởng sản xuất ở Đức Dương.'),
  'mianyang/libai': ('Quê hương Lý Bạch', 'Thi tiên Lý Bạch lớn lên giữa những ngọn núi ở Giang Du, nơi những vần thơ của ông vẫn còn vang vọng đến tận ngày nay.'),
  'mianyang/sciencecity': ('Thành phố Khoa học', 'Là thành phố duy nhất tại Trung Quốc được mệnh danh là \'Thành phố Khoa học và Công nghệ\', nơi đây đang kiến tạo tương lai bằng các phòng thí nghiệm và công nghệ hiện đại.'),
  'mianyang/qiang': ('Tháp đá người Khương', 'Tại các bản làng miền núi Bắc Xuyên, những tòa tháp canh bằng đá của người Khương đã đứng vững qua hàng thế kỷ.'),
  'mianyang/mifen': ('Bún gạo Miên Dương', 'Bún gạo sợi mảnh chan nước dùng gà và nội tạng nóng hổi là món ăn sáng quen thuộc đánh thức cả thành phố mỗi ngày.'),
  'nanchong/langzhong': ('Cổ trấn Lãng Trung', 'Được quy hoạch theo phong thủy, cổ trấn được bảo tồn tốt nhất này nằm yên bình trong vòng tay uốn lượn của dòng sông.'),
  'nanchong/silk': ('Thủ phủ tơ lụa', 'Với lịch sử dệt may kéo dài hai nghìn năm, Nam Sung được mệnh danh là thủ phủ tơ lụa ở miền Tây Trung Quốc.'),
  'nanchong/zhangfei': ('Thịt bò Trương Phi', 'Món thịt bò ướp gia vị đặc sản từ thành phố của vị tướng thời Tam Quốc - Trương Phi - được đặt theo tên của ông.'),
  'nanchong/zhude': ('Quê hương Chu Đức', 'Ngôi nhà giản dị của Nguyên soái Chu Đức tại Nghi Long là một điểm đến lịch sử quan trọng đối với du khách.'),
  'yibin/wuliangye': ('Rượu Ngũ Lương Dịch', 'Được chưng cất từ năm loại ngũ cốc, Ngũ Lương Dịch là một trong những thương hiệu bạch tửu quý giá nhất Trung Quốc.'),
  'yibin/firstcity': ('Thành phố đầu nguồn sông Dương Tử', 'Nơi hợp lưu của sông Mân và sông Kim Sa tạo nên dòng Dương Tử, vì vậy Nghi Bình được gọi là \'thành phố đầu nguồn\'.'),
  'yibin/bamboosea': ('Thục Nam Trúc Hải', 'Một đại dương tre bao phủ hơn một trăm hai mươi ngọn đồi, đung đưa như những con sóng xanh trong gió.'),
  'yibin/ranmian': ('Mì đốt (Ranmian)', 'Được trộn khô đến mức dầu có thể bắt lửa, \'mì đốt\' là món ăn sáng trứ danh đầy hương vị của Nghi Bình.'),
  'luzhou/laojiao': ('Hầm rượu Lão Giao', 'Những hầm ủ rượu bằng bùn được sử dụng liên tục từ năm 1573 là linh hồn tạo nên hương vị đặc trưng của rượu bạch tửu.'),
  'luzhou/port': ('Cảng sông Dương Tử', 'Thành phố cảng nằm tại nơi giao nhau của hai dòng sông này chính là cửa ngõ đường thủy của Tứ Xuyên hướng ra biển.'),
  'luzhou/longan': ('Vườn nhãn', 'Được trồng trên những sườn đồi ấm áp ven sông, nhãn là loại quả ngọt lịm thường được gọi là \'mắt rồng\'.'),
  'luzhou/umbrella': ('Ô giấy dầu', 'Những chiếc ô giấy dầu thủ công của các nghệ nhân Phân Thủy là một di sản tinh tế đã tồn tại suốt bốn trăm năm.'),
  'leshan/giantbuddha': ('Lạc Sơn Đại Phật', 'Bức tượng Phật ngồi cao 71 mét được tạc vào vách đá đã trấn giữ nơi hợp lưu của các dòng sông suốt mười hai thế kỷ qua.'),
  'leshan/emei': ('Núi Nga Mi', 'Đỉnh Kim Đỉnh của núi Nga Mi, một trong bốn ngọn núi thiêng của Phật giáo, tỏa sáng rực rỡ trên biển mây.'),
  'leshan/monkeys': ('Khỉ Nga Mi', 'Những chú khỉ tinh nghịch trên các lối mòn lên núi nổi tiếng với việc táo bạo lục lọi túi xách của du khách hành hương.'),
  'leshan/qiaojiao': ('Canh bò Kiều Cước', 'Canh bò hầm thảo mộc \'Kiều Cước\' là món ăn kinh điển có lịch sử hàng trăm năm trên các bàn ăn đường phố Lạc Sơn.'),
  'zigong/saltwell': ('Giếng muối sâu nghìn mét', 'Giếng Thâm Hải, giếng muối đầu tiên trên thế giới vượt độ sâu một nghìn mét, là niềm tự hào của thành phố muối hai ngàn năm tuổi.'),
  'zigong/lantern': ('Lễ hội đèn lồng Tự Cống', 'Những khu vườn với hàng ngàn chiếc đèn lồng khổng lồ rực rỡ biến thành phố này thành một thế giới thần tiên mỗi dịp năm mới.'),
  'zigong/dinosaur': ('Bảo tàng Khủng long', 'Hàng ngàn hóa thạch được khai quật từ các tầng địa chất kỷ Jura đã đưa Tự Cống trở thành thủ phủ khủng long của Trung Quốc.'),
  'zigong/rabbit': ('Thỏ lạnh', 'Món thỏ lạnh cay nồng là đặc sản trứ danh của thành phố này, đồng thời là món khai vị đậm đà nhất của ẩm thực Tứ Xuyên.'),
  'panzhihua/steel': ('Thủ phủ Vanadi-Titan', 'Thành phố thép khổng lồ được xây dựng giữa lòng núi này đang khai thác những mỏ vanadi và titan phong phú nhất thế giới.'),
  'panzhihua/fruitvalley': ('Thung lũng trái cây ngập nắng', 'Xoài và lựu ở thung lũng khô nóng này chín mọng dưới ánh mặt trời ngay cả trong mùa đông.'),
  'panzhihua/sunshine': ('Thành phố nắng mùa đông', 'Với 2.700 giờ nắng mỗi năm, Phàn Chi Hoa là điểm đến lý tưởng để tận hưởng mùa đông ôn hòa và chăm sóc sức khỏe.'),
  'panzhihua/jinsha': ('Sông Kim Sa', 'Dòng sông Kim Sa với những bãi cát vàng cuồn cuộn chảy qua thành phố, tạo nên những thung lũng sâu thẳm.'),
  'dazhou/gas': ('Thủ phủ khí đốt', 'Mỏ khí Puguang khổng lồ đã biến Đạt Châu thành trung tâm năng lượng khí đốt quan trọng của Trung Quốc.'),
  'dazhou/ba': ('Di sản nước Ba', 'Vùng đất của những chiến binh nước Ba cổ đại với thanh kiếm lá liễu vẫn đang kể câu chuyện lịch sử qua di chỉ La Gia Bá.'),
  'dazhou/dengying': ('Thịt bò Đăng Ảnh', 'Những lát thịt bò mỏng tang có thể nhìn thấu qua ánh sáng, cái tên \'Đăng Ảnh\' bắt nguồn từ nghệ thuật múa bóng truyền thống.'),
  'dazhou/hanque': ('Khuyết đá thời Hán', 'Những tòa khuyết đá hai nghìn năm tuổi tại huyện Cừ là minh chứng còn sót lại cho vẻ đẹp kiến trúc thời Hán.'),
  'guangyuan/jianmen': ('Kiếm Môn Quan', 'Cửa ải hiểm trở với địa thế \'một người giữ cửa, vạn người không thể vượt\' được coi là chìa khóa của con đường vào đất Thục.'),
  'guangyuan/wuzetian': ('Quê hương Võ Tắc Thiên', 'Nữ hoàng đế duy nhất trong lịch sử Trung Quốc, Võ Tắc Thiên, đã sinh ra tại đây và được thờ phụng tại chùa Hoàng Trạch suốt hàng ngàn năm qua.'),
  'guangyuan/plankroad': ('Sạn đạo cổ', 'Những con đường ván gỗ đóng trên vách đá cheo leo là biểu tượng cho sự dũng cảm trên con đường vào Thục vốn \'khó hơn lên trời\'.'),
  'guangyuan/cypress': ('Hành lang bách Thúy Vân', 'Hàng chục ngàn cây bách cổ thụ từ thời Tam Quốc biến con đường xưa thành một đường hầm xanh mát.'),
  'yaan/panda': ('Cái nôi của gấu trúc', 'Gấu trúc lớn lần đầu tiên được giới khoa học ghi nhận tại Bảo Hưng vào năm 1869, và khu bảo tồn Bích Phong Hạp vẫn đang tiếp nối di sản đó.'),
  'yaan/rain': ('Thành phố mưa', 'Những cơn mưa Nhã An hầu như đêm nào cũng gột rửa mái nhà, khiến thành phố luôn bừng sáng trong sắc xanh mướt.'),
  'yaan/mengding': ('Trà núi Mông Đỉnh', 'Trà được con người trồng lần đầu tiên trên núi Mông Đỉnh cách đây hai nghìn năm, nơi đây được coi là cái nôi của văn hóa trà đạo.'),
  'yaan/yayu': ('Cá Nhã', 'Loài cá Nhã huyền thoại từ những dòng suối băng tan là niềm tự hào của thành phố, thường được chế biến trong những nồi lẩu nghi ngút khói.'),
  'xianyang/qincapital': ('Kinh đô nhà Tần', 'Đây từng là kinh đô của nhà Tần, triều đại đầu tiên thống nhất Trung Quốc, nơi con đường dẫn đến đế chế bắt đầu từ Hàm Dương.'),
  'xianyang/qianling': ('Càn Lăng', 'Ngôi mộ chung của Võ Tắc Thiên và chồng bà nằm trên núi, thách thức lịch sử với tấm bia không chữ đầy bí ẩn.'),
  'xianyang/zhengguo': ('Kênh Trịnh Quốc', 'Con kênh thủy lợi có lịch sử hai nghìn năm này đã biến đồng bằng Quan Trung thành vựa lúa của nhà Tần.'),
  'xianyang/guokui': ('Bánh quách khôi', 'Bánh quách khôi giòn rụm to như nắp nồi là món ăn vặt truyền thống lâu đời trên bàn ăn của người Thiểm Tây.'),
  'baoji/bronze': ('Thủ phủ đồ đồng', 'Hàng nghìn cổ vật đồ đồng thời Chu, bao gồm cả chiếc Hà tôn có khắc chữ \'Trung Quốc\' đầu tiên, đã được tìm thấy tại Bảo Kê.'),
  'baoji/famen': ('Chùa Pháp Môn', 'Nơi lưu giữ xá lợi xương ngón tay của Đức Phật, chùa Pháp Môn từng là kho báu linh thiêng của các hoàng đế nhà Đường.'),
  'baoji/taibai': ('Núi Thái Bạch', 'Với độ cao 3.771 mét, đỉnh Thái Bạch là nóc nhà của dãy Tần Lĩnh, nổi tiếng với cảnh tượng tuyết phủ ngay cả trong mùa hè.'),
  'baoji/saozi': ('Mì sao tử', 'Mì sao tử Kỳ Sơn với nước dùng chua cay là hương vị sống động còn lưu giữ từ nghệ thuật ẩm thực thời nhà Chu cách đây ba nghìn năm.'),
};
